#!/usr/bin/env bash
# install.sh — LLM API Proxy installer
# Generated by build-installer.sh — do not edit manually.
#
# Usage: curl -fsSL .../install.sh | sudo bash
#        sudo bash install.sh [install|upgrade|reconfigure|uninstall] [OPTIONS]

set -euo pipefail

# ── Pipe-to-bash guarantee ────────────────────────────────────────────────────
# Wrapping the entire body in _main() forces bash to read all of stdin (looking
# for the closing '}') before executing anything.  This guarantees that all
# variable definitions—including EMBED_* injected at the bottom by
# build-installer.sh—are parsed and available before main() runs.
# The old tmpfile re-exec pattern is no longer needed.
_main() {

# ── Constants ────────────────────────────────────────────────────────────────
INSTALLER_VERSION="0.0.33"
# shellcheck disable=SC2034  # Used by phase functions appended by build-installer.sh
INSTALL_DIR_LINUX="/opt/llm-api-proxy"
# shellcheck disable=SC2034
INSTALL_DIR_MACOS="/usr/local/lib/llm-api-proxy"
# shellcheck disable=SC2034
METADATA_DIR_LINUX="/etc/llm-api-proxy"
# shellcheck disable=SC2034
METADATA_DIR_MACOS="${HOME}/.config/llm-api-proxy"
# shellcheck disable=SC2034
SERVICE_USER="llm-proxy"
LOG_FILE="/tmp/llm-api-proxy-install-$(date +%Y%m%d-%H%M%S).log"
CLEANUP_FILES=()

# Privilege escalation — empty when already root, "sudo" otherwise
if [[ $EUID -eq 0 ]]; then
    SUDO=""
else
    SUDO="sudo"
fi

# ── Security ─────────────────────────────────────────────────────────────────
umask 077

# ── Signal traps ─────────────────────────────────────────────────────────────
cleanup() {
    local file
    for file in "${CLEANUP_FILES[@]}"; do
        rm -f "$file" 2>/dev/null || true
    done
    if [[ "${INSTALL_PHASE:-}" != "" ]]; then
        echo ""
        echo "Installation interrupted during: ${INSTALL_PHASE}"
        echo "System state: phases before '${INSTALL_PHASE}' completed successfully."
        echo "Re-run install.sh to resume."
        echo ""
    fi
}
trap cleanup EXIT
trap 'cleanup; exit 130' INT
trap 'cleanup; exit 143' TERM

# ── Colour output ────────────────────────────────────────────────────────────
if [[ -t 1 ]] && command -v tput &>/dev/null; then
    RED=$(tput setaf 1)
    GREEN=$(tput setaf 2)
    YELLOW=$(tput setaf 3)
    # shellcheck disable=SC2034  # BLUE used by phase functions appended by build-installer.sh
    BLUE=$(tput setaf 4)
    BOLD=$(tput bold)
    RESET=$(tput sgr0)
else
    RED="" GREEN="" YELLOW=""
    # shellcheck disable=SC2034
    BLUE="" BOLD="" RESET=""
fi

# ── Logging ──────────────────────────────────────────────────────────────────
log_init() {
    local safe_args
    safe_args=$(echo "$*" | sed -E 's/(--github-token=)[^ ]*/\1***REDACTED***/g')
    touch "$LOG_FILE"
    chmod 0600 "$LOG_FILE"
    {
        echo "=== LLM API Proxy Installer v${INSTALLER_VERSION} ==="
        echo "Date: $(date -u +%Y-%m-%dT%H:%M:%SZ)"
        echo "User: $(whoami)"
        echo "Args: ${safe_args}"
        echo "---"
    } >> "$LOG_FILE"
}

log() { echo "[$(date -u +%H:%M:%S)] $*" >> "$LOG_FILE"; }

info()  { echo "${GREEN}  ✓${RESET} $*"; log "INFO: $*"; }
warn()  { echo "${YELLOW}  ⚠${RESET} $*"; log "WARN: $*"; }
fail()  { echo "${RED}  ✗${RESET} $*"; log "FAIL: $*"; }
step()  { echo "${BOLD}$*${RESET}"; log "STEP: $*"; }

die() {
    fail "$1"
    echo ""
    echo "Full log: ${LOG_FILE}"
    exit "${2:-1}"
}

# Mask secrets in log output
mask_secret() {
    local val="$1"
    if [[ ${#val} -le 4 ]]; then
        echo "****"
    else
        echo "${val:0:2}***${val: -2}"
    fi
}

# ── Box drawing ──────────────────────────────────────────────────────────────
draw_box() {
    local title="$1"
    shift
    local width=50
    local top_line bottom_line
    top_line="╔$(printf '═%.0s' $(seq 1 $((width - 2))))╗"
    bottom_line="╚$(printf '═%.0s' $(seq 1 $((width - 2))))╝"
    echo "$top_line"
    printf "║  %-$((width - 4))s║\n" "$title"
    echo "╠$(printf '═%.0s' $(seq 1 $((width - 2))))╣"
    for line in "$@"; do
        printf "║  %-$((width - 4))s║\n" "$line"
    done
    echo "$bottom_line"
}

# ── Dialog / whiptail wrapper ────────────────────────────────────────────────
DIALOG_CMD=""

detect_dialog() {
    if command -v dialog &>/dev/null; then
        DIALOG_CMD="dialog"
    elif command -v whiptail &>/dev/null; then
        DIALOG_CMD="whiptail"
    fi
}

# Returns 0=yes, 1=no. Falls back to read prompt if no dialog.
ask_yesno() {
    local title="$1" text="$2" default="${3:-yes}"
    if [[ -n "$DIALOG_CMD" ]] && [[ -t 0 ]]; then
        local flags=()
        if [[ "$default" != "yes" ]]; then
            flags+=(--defaultno)
        fi
        "$DIALOG_CMD" "${flags[@]}" --title "$title" --yesno "$text" 12 60
        return $?
    else
        local prompt
        if [[ "$default" == "yes" ]]; then
            prompt="$text [Y/n]: "
        else
            prompt="$text [y/N]: "
        fi
        local answer
        read -r -p "$prompt" answer
        case "${answer,,}" in
            y|yes) return 0 ;;
            n|no)  return 1 ;;
            "")    [[ "$default" == "yes" ]] && return 0 || return 1 ;;
            *)     return 1 ;;
        esac
    fi
}

# Input box. Returns value on stdout. Falls back to read.
ask_input() {
    local title="$1" text="$2" default="${3:-}"
    if [[ -n "$DIALOG_CMD" ]] && [[ -t 0 ]]; then
        local result
        # On Escape/cancel, fall back to default rather than propagating non-zero exit
        # (which would kill the script under set -e)
        result=$("$DIALOG_CMD" --title "$title" --inputbox "$text" 10 60 "$default" 3>&1 1>&2 2>&3) \
            || { echo "$default"; return 0; }
        echo "$result"
    else
        local answer
        if [[ -n "$default" ]]; then
            read -r -p "$text [$default]: " answer
            echo "${answer:-$default}"
        else
            read -r -p "$text: " answer
            echo "$answer"
        fi
    fi
}

# Password input (hidden). Falls back to read -s.
ask_password() {
    local title="$1" text="$2"
    if [[ -n "$DIALOG_CMD" ]] && [[ -t 0 ]]; then
        local result
        # On Escape/cancel, return empty string rather than propagating non-zero exit
        result=$("$DIALOG_CMD" --title "$title" --passwordbox "$text" 10 60 3>&1 1>&2 2>&3) \
            || { echo ""; return 0; }
        echo "$result"
    else
        local answer
        read -r -s -p "$text: " answer
        echo ""  # newline after hidden input
        echo "$answer"
    fi
}

# Checklist. Returns space-separated selected items. Falls back to numbered menu.
ask_checklist() {
    local title="$1" text="$2"
    shift 2
    # Remaining args: tag description on/off triplets
    if [[ -n "$DIALOG_CMD" ]] && [[ -t 0 ]]; then
        local result
        local height=$(( ($# / 3) + 8 ))
        result=$("$DIALOG_CMD" --title "$title" --checklist "$text" "$height" 60 $(($# / 3)) "$@" 3>&1 1>&2 2>&3) || return 1
        echo "$result"
    else
        echo "$text"
        local i=0
        local tags=()
        local descs=()
        local states=()
        while [[ $# -gt 0 ]]; do
            tags+=("$1"); descs+=("$2"); states+=("$3")
            shift 3
            i=$((i + 1))
        done
        for ((j=0; j<${#tags[@]}; j++)); do
            local marker=" "
            [[ "${states[$j]}" == "on" ]] && marker="X"
            echo "  [$marker] $((j+1)). ${descs[$j]}"
        done
        local selected
        # shellcheck disable=SC2034  # `selected` read but intentionally discarded; toggle logic is a future enhancement
        read -r -p "Enter numbers to toggle (e.g., 1 3), or press Enter to accept: " selected
        # Return tags that are currently enabled (simplified fallback — toggle logic in future)
        local result=""
        for ((j=0; j<${#tags[@]}; j++)); do
            if [[ "${states[$j]}" == "on" ]]; then
                result+="${tags[$j]} "
            fi
        done
        echo "$result"
    fi
}

# Single-select radiolist. Returns the tag of the selected item. Falls back to numbered menu.
ask_radiolist() {
    local title="$1" text="$2"
    shift 2
    # Remaining args: tag description on|off triplets (exactly one should be "on")
    if [[ -n "$DIALOG_CMD" ]] && [[ -t 0 ]]; then
        local height=$(( ($# / 3) + 8 ))
        local result
        result=$("$DIALOG_CMD" --title "$title" --radiolist "$text" "$height" 60 $(($# / 3)) "$@" 3>&1 1>&2 2>&3) || return 1
        echo "$result"
    else
        echo "$text"
        local tags=() descs=() states=()
        while [[ $# -gt 0 ]]; do
            tags+=("$1"); descs+=("$2"); states+=("$3")
            shift 3
        done
        local default_idx=0
        for ((j=0; j<${#tags[@]}; j++)); do
            local marker=" "
            if [[ "${states[$j]}" == "on" ]]; then
                marker="*"
                default_idx=$((j + 1))
            fi
            echo "  ($marker) $((j+1)). ${descs[$j]}"
        done
        local answer
        # `read` returns 1 on EOF (e.g., non-interactive pipe); `|| true` prevents set -e from aborting
        read -r -p "Enter number [${default_idx}]: " answer || true
        answer="${answer:-$default_idx}"
        # Validate and return tag
        if [[ "$answer" =~ ^[0-9]+$ ]] && (( answer >= 1 && answer <= ${#tags[@]} )); then
            echo "${tags[$((answer - 1))]}"
        else
            # Fall back to the pre-selected default
            echo "${tags[$((default_idx - 1))]}"
        fi
    fi
}

# ── Embedded file extraction ─────────────────────────────────────────────────
extract_file() {
    local var_name="$1" dest="$2" mode="${3:-0640}"
    if [[ -z "${!var_name:-}" ]]; then
        warn "Embedded file '${var_name}' not available — skipping ${dest}"
        return 0
    fi
    $SUDO mkdir -p "$(dirname "$dest")"
    echo "${!var_name}" | base64 -d | $SUDO tee "$dest" > /dev/null
    $SUDO chmod "$mode" "$dest"
}

# ── CLI argument parsing ─────────────────────────────────────────────────────
