COMMAND=""
OPT_VERSION=""
OPT_INSTALL_DIR=""
OPT_NON_INTERACTIVE="false"
OPT_ACCEPT_TOS="false"
OPT_SKIP_SYSTEM_UPGRADE="false"
OPT_SKIP_FIREWALL="false"
OPT_SKIP_SECURITY_UPDATES="false"
OPT_SKIP_CHECKSUM="false"

