show_usage() {
    cat <<'USAGE'
LLAP — LLM API Proxy Installer

Usage: install.sh [COMMAND] [OPTIONS]

Commands:
  install         Fresh installation (default if no existing installation)
  upgrade         Upgrade to latest or specified version
  reconfigure     Change settings on existing installation
  uninstall       Remove installation (preserves data unless --purge)

General:
  --help                  Show this usage information and exit
  --installer-version     Show installer version and exit

Authentication:
  --github-token=TOKEN    GitHub PAT for authenticated GHCR access
  --github-user=USER      GitHub username for docker login

  Token precedence (highest to lowest):
    1. --github-token= (CLI flag)
    2. PROXY_INSTALL_GITHUB_TOKEN (env var)
    3. CR_PAT (env var)
    4. GH_TOKEN (env var)
    5. GITHUB_TOKEN (env var)

  If multiple sources provide different values, a warning is emitted and the
  highest-precedence value is used. If no token is set, the installer works
  identically to before (unauthenticated).

  Security: prefer env vars over --github-token= to avoid token exposure in
  ps output and shell history.

  References:
    CR_PAT:       https://docs.github.com/en/packages/working-with-a-github-packages-registry/working-with-the-container-registry
    GH_TOKEN:     https://cli.github.com/manual/gh_help_environment
    GITHUB_TOKEN: https://docs.github.com/en/actions/security-for-github-actions/security-guides/automatic-token-authentication

Options:
  --version=VER           Pin image version (e.g., 0.1.0, edge)
  --install-dir=PATH      Override install directory
  --non-interactive       Never prompt, fail if required values missing
  --accept-tos            Accept Terms of Service (required for --non-interactive)
  --skip-system-upgrade   Don't offer OS package upgrade
  --skip-firewall         Don't touch firewall rules
  --skip-security-updates Don't configure unattended-upgrades
  --skip-checksum         Skip remote checksum verification

Features (all ON by default):
  --no-waf                Disable ModSecurity WAF
  --no-tls                Disable TLS/HTTPS
  --no-backup             Disable backup agent
  --no-monitoring         Disable Prometheus + Grafana
  --no-mdns               Disable mDNS (always disabled on macOS)

Core:
  --postgres-password=    DB password (auto-generated if omitted)
  --kek-hex=              Encryption key (auto-generated if omitted)
  --proxy-key-pepper=HEX  64-char hex proxy key HMAC pepper (auto-generated if not set)
                          MUST match source server for credential migrations
  --listen-port=          Proxy HTTP service port (default: 7080)
  --forward-proxy-port=   Forward proxy CONNECT port (default: 7443)

TLS:
  --domain=               Public hostname
  --acme-email=           Let's Encrypt email
  --cf-dns-api-token=     Cloudflare scoped API token
  --cf-api-email=         Cloudflare global key email (legacy)
  --cf-api-key=           Cloudflare global API key (legacy)

Backup:
  --restic-repository=    Restic repo URL
  --restic-password=      Restic encryption password
  --aws-access-key-id=    S3 access key
  --aws-secret-access-key= S3 secret key
  --backup-schedule=      Cron expression (default: "0 2 * * *")

Monitoring:
  --grafana-password=     Grafana admin password (auto-generated)
  --grafana-port=         Grafana port (default: 3000)
  --prometheus-port=      Prometheus port (default: 9090)

Uninstall:
  --purge                 Also remove Docker volumes (DATABASE LOSS)

Debug containers:
  --debug                 Enable debug-mode sidecar containers
  --debug-profile=PROFILE Debug detail level: minimal, moderate, or full (default: moderate)
  --no-debug              Disable debug-mode sidecar containers (overrides --debug and env vars)

  Env vars:
    PROXY_INSTALL_DEBUG=true|false
    PROXY_INSTALL_DEBUG_PROFILE=minimal|moderate|full

  Note: --debug-profile= without effective debug mode (i.e. when --no-debug is also given)
        is validated after .env state is loaded, not during argument parsing.
USAGE
}

# shellcheck disable=SC2034  # All variables set here are used by phase functions appended by build-installer.sh
parse_args() {
    while [[ $# -gt 0 ]]; do
        case "$1" in
            install|upgrade|reconfigure|uninstall)
                COMMAND="$1" ;;
            --help|-h)
                show_usage; exit 0 ;;
            --installer-version)
                echo "install.sh version ${INSTALLER_VERSION}"; exit 0 ;;
            --version=*)          OPT_VERSION="${1#*=}"; OPT_VERSION="${OPT_VERSION#v}" ;;
            --install-dir=*)      OPT_INSTALL_DIR="${1#*=}" ;;
            --non-interactive)    OPT_NON_INTERACTIVE="true" ;;
            --accept-tos)         OPT_ACCEPT_TOS="true" ;;
            --skip-system-upgrade) OPT_SKIP_SYSTEM_UPGRADE="true" ;;
            --skip-firewall)      OPT_SKIP_FIREWALL="true" ;;
            --skip-security-updates) OPT_SKIP_SECURITY_UPDATES="true" ;;
            --skip-checksum)      OPT_SKIP_CHECKSUM="true" ;;
            --no-waf)             OPT_WAF="false" ;;
            --no-tls)             OPT_TLS="false" ;;
            --no-backup)          OPT_BACKUP="false" ;;
            --no-monitoring)      OPT_MONITORING="false" ;;
            --no-mdns)            OPT_MDNS="false" ;;
            --postgres-password=*) OPT_POSTGRES_PASSWORD="${1#*=}" ;;
            --kek-hex=*)          OPT_KEK_HEX="${1#*=}" ;;
            --proxy-key-pepper=*) OPT_PROXY_KEY_PEPPER="${1#*=}" ;;
            --listen-port=*)      OPT_LISTEN_PORT="${1#*=}" ;;
            --forward-proxy-port=*) OPT_FORWARD_PROXY_PORT="${1#*=}" ;;
            --domain=*)           OPT_DOMAIN="${1#*=}" ;;
            --acme-email=*)       OPT_ACME_EMAIL="${1#*=}" ;;
            --cf-dns-api-token=*) OPT_CF_DNS_API_TOKEN="${1#*=}" ;;
            --cf-api-email=*)     OPT_CF_API_EMAIL="${1#*=}" ;;
            --cf-api-key=*)       OPT_CF_API_KEY="${1#*=}" ;;
            --restic-repository=*) OPT_RESTIC_REPOSITORY="${1#*=}" ;;
            --restic-password=*)  OPT_RESTIC_PASSWORD="${1#*=}" ;;
            --aws-access-key-id=*) OPT_AWS_ACCESS_KEY_ID="${1#*=}" ;;
            --aws-secret-access-key=*) OPT_AWS_SECRET_ACCESS_KEY="${1#*=}" ;;
            --backup-schedule=*)  OPT_BACKUP_SCHEDULE="${1#*=}" ;;
            --grafana-password=*) OPT_GRAFANA_PASSWORD="${1#*=}" ;;
            --grafana-port=*)     OPT_GRAFANA_PORT="${1#*=}" ;;
            --prometheus-port=*)  OPT_PROMETHEUS_PORT="${1#*=}" ;;
            --purge)              OPT_PURGE="true" ;;
            --github-token=*)     OPT_GITHUB_TOKEN="${1#*=}" ;;
            --github-user=*)      OPT_GITHUB_USER="${1#*=}" ;;
            --debug)              OPT_DEBUG="true" ;;
            --debug-profile=*)
                OPT_DEBUG_PROFILE="${1#*=}"
                OPT_DEBUG_PROFILE_SET="true"
                case "$OPT_DEBUG_PROFILE" in
                    minimal|moderate|full) ;;
                    *) die "--debug-profile must be minimal, moderate, or full (got: $OPT_DEBUG_PROFILE)" ;;
                esac ;;
            --no-debug)           OPT_NO_DEBUG="true" ;;
            *)
                die "Unknown option: $1. Run with --help for usage." ;;
        esac
        shift
    done
}

# ── PROXY_INSTALL_* environment variable fallback ────────────────────────────
# CLI flags take precedence. Env vars fill in anything not set via CLI.
# Spec Section 7.9: CLI > env vars > existing .env > interactive prompts.
apply_env_defaults() {
    [[ -z "$OPT_VERSION" ]]            && OPT_VERSION="${PROXY_INSTALL_VERSION:-}"; OPT_VERSION="${OPT_VERSION#v}"
    [[ -z "$OPT_DOMAIN" ]]             && OPT_DOMAIN="${PROXY_INSTALL_DOMAIN:-}"
    [[ -z "$OPT_ACME_EMAIL" ]]         && OPT_ACME_EMAIL="${PROXY_INSTALL_ACME_EMAIL:-}"
    [[ -z "$OPT_CF_DNS_API_TOKEN" ]]   && OPT_CF_DNS_API_TOKEN="${PROXY_INSTALL_CF_DNS_API_TOKEN:-}"
    [[ -z "$OPT_CF_API_EMAIL" ]]       && OPT_CF_API_EMAIL="${PROXY_INSTALL_CF_API_EMAIL:-}"
    [[ -z "$OPT_CF_API_KEY" ]]         && OPT_CF_API_KEY="${PROXY_INSTALL_CF_API_KEY:-}"
    [[ -z "$OPT_POSTGRES_PASSWORD" ]]  && OPT_POSTGRES_PASSWORD="${PROXY_INSTALL_POSTGRES_PASSWORD:-}"
    [[ -z "$OPT_KEK_HEX" ]]           && OPT_KEK_HEX="${PROXY_INSTALL_KEK_VALUE:-}"
    [[ -z "$OPT_PROXY_KEY_PEPPER" ]] && OPT_PROXY_KEY_PEPPER="${PROXY_INSTALL_PROXY_KEY_PEPPER:-}"
    [[ -z "$OPT_RESTIC_REPOSITORY" ]]  && OPT_RESTIC_REPOSITORY="${PROXY_INSTALL_RESTIC_REPOSITORY:-}"
    [[ -z "$OPT_RESTIC_PASSWORD" ]]    && OPT_RESTIC_PASSWORD="${PROXY_INSTALL_RESTIC_PASSWORD:-}"
    [[ -z "$OPT_AWS_ACCESS_KEY_ID" ]]  && OPT_AWS_ACCESS_KEY_ID="${PROXY_INSTALL_AWS_ACCESS_KEY_ID:-}"
    [[ -z "$OPT_AWS_SECRET_ACCESS_KEY" ]] && OPT_AWS_SECRET_ACCESS_KEY="${PROXY_INSTALL_AWS_SECRET_ACCESS_KEY:-}"
    [[ -z "$OPT_GRAFANA_PASSWORD" ]]   && OPT_GRAFANA_PASSWORD="${PROXY_INSTALL_GRAFANA_PASSWORD:-}"
    [[ "$OPT_NON_INTERACTIVE" == "false" ]] && [[ "${PROXY_INSTALL_NON_INTERACTIVE:-}" == "true" ]] && OPT_NON_INTERACTIVE="true"
    [[ "$OPT_ACCEPT_TOS" == "false" ]] && [[ "${PROXY_INSTALL_ACCEPT_TOS:-}" == "true" ]] && OPT_ACCEPT_TOS="true"
    if [[ -z "$OPT_GITHUB_TOKEN" ]]; then OPT_GITHUB_TOKEN="${PROXY_INSTALL_GITHUB_TOKEN:-}"; fi
    if [[ -z "$OPT_GITHUB_USER" ]];  then OPT_GITHUB_USER="${PROXY_INSTALL_GITHUB_USER:-}";  fi
    # Debug container env var fallbacks — only apply when not set via CLI flags
    if [[ "$OPT_DEBUG" == "false" ]] && [[ "$OPT_NO_DEBUG" == "false" ]]; then
        [[ "${PROXY_INSTALL_DEBUG:-}" == "true" ]] && OPT_DEBUG="true"
    fi
    if [[ "$OPT_DEBUG_PROFILE_SET" == "false" ]] && [[ -n "${PROXY_INSTALL_DEBUG_PROFILE:-}" ]]; then
        case "${PROXY_INSTALL_DEBUG_PROFILE}" in
            minimal|moderate|full)
                OPT_DEBUG_PROFILE="${PROXY_INSTALL_DEBUG_PROFILE}"
                OPT_DEBUG_PROFILE_SET="true"
                ;;
            *) die "PROXY_INSTALL_DEBUG_PROFILE must be minimal, moderate, or full (got: ${PROXY_INSTALL_DEBUG_PROFILE})" ;;
        esac
    fi
    # --no-debug always wins: if set, force OPT_DEBUG=false regardless of other flags or env vars
    if [[ "$OPT_NO_DEBUG" == "true" ]]; then
        OPT_DEBUG="false"
    fi
}

# ── GitHub token resolution ───────────────────────────────────────────────────
# Resolves a GitHub PAT from 5 sources in precedence order.
# Sets GITHUB_TOKEN_RESOLVED. Warns on conflict (different values from multiple sources).
# Precedence: CLI --github-token= > PROXY_INSTALL_GITHUB_TOKEN > CR_PAT > GH_TOKEN > GITHUB_TOKEN
resolve_github_token() {
    local -a sources=()
    local -a values=()

    # 1. CLI flag (--github-token=) or PROXY_INSTALL_GITHUB_TOKEN
    #    apply_env_defaults() folds PROXY_INSTALL_GITHUB_TOKEN into OPT_GITHUB_TOKEN,
    #    so we distinguish by checking the raw env var.
    if [[ -n "${OPT_GITHUB_TOKEN:-}" ]]; then
        if [[ -n "${PROXY_INSTALL_GITHUB_TOKEN:-}" ]] && [[ "$OPT_GITHUB_TOKEN" == "$PROXY_INSTALL_GITHUB_TOKEN" ]]; then
            sources+=("--github-token / PROXY_INSTALL_GITHUB_TOKEN")
        else
            sources+=("--github-token")
        fi
        values+=("$OPT_GITHUB_TOKEN")
    elif [[ -n "${PROXY_INSTALL_GITHUB_TOKEN:-}" ]]; then
        sources+=("PROXY_INSTALL_GITHUB_TOKEN")
        values+=("$PROXY_INSTALL_GITHUB_TOKEN")
    fi

    # 2-4. Direct env vars (in precedence order)
    [[ -n "${CR_PAT:-}" ]]       && sources+=("CR_PAT")       && values+=("$CR_PAT")
    [[ -n "${GH_TOKEN:-}" ]]     && sources+=("GH_TOKEN")     && values+=("$GH_TOKEN")
    [[ -n "${GITHUB_TOKEN:-}" ]] && sources+=("GITHUB_TOKEN") && values+=("$GITHUB_TOKEN")

    if [[ ${#values[@]} -eq 0 ]]; then
        log "GitHub token: no token found in any source"
        return 0
    fi

    # Set resolved token to highest-precedence value
    GITHUB_TOKEN_RESOLVED="${values[0]}"
    local winner_source="${sources[0]}"

    # Detect conflicts: check if any other source has a different value
    local i
    for (( i=1; i<${#values[@]}; i++ )); do
        if [[ "${values[$i]}" != "$GITHUB_TOKEN_RESOLVED" ]]; then
            warn "Multiple GitHub token sources with different values. Using ${winner_source}. Ignoring: ${sources[$i]}"
        fi
    done

    log "GitHub token resolved from: ${winner_source} (value: $(mask_secret "$GITHUB_TOKEN_RESOLVED"))"
}

# ── GitHub username detection ─────────────────────────────────────────────────
# Resolves GitHub username for docker login from CLI flag, env vars, or API.
# Sets GITHUB_USER_RESOLVED. Only meaningful when GITHUB_TOKEN_RESOLVED is set.
# Precedence: OPT_GITHUB_USER > GITHUB_USER env var > GitHub API auto-detect
detect_github_user() {
    # 1. CLI flag or PROXY_INSTALL_GITHUB_USER (both folded into OPT_GITHUB_USER)
    if [[ -n "${OPT_GITHUB_USER:-}" ]]; then
        GITHUB_USER_RESOLVED="$OPT_GITHUB_USER"
        log "GitHub user resolved from OPT_GITHUB_USER: ${GITHUB_USER_RESOLVED}"
        return 0
    fi

    # 2. GITHUB_USER env var
    if [[ -n "${GITHUB_USER:-}" ]]; then
        GITHUB_USER_RESOLVED="$GITHUB_USER"
        log "GitHub user resolved from GITHUB_USER env var: ${GITHUB_USER_RESOLVED}"
        return 0
    fi

    # 3. Auto-detect via GitHub API (requires GITHUB_TOKEN_RESOLVED)
    if [[ -z "${GITHUB_TOKEN_RESOLVED:-}" ]]; then
        log "GitHub user: no token available, skipping API auto-detect"
        return 0
    fi

    local api_response login
    if api_response=$(curl -fsSL --max-time 10 \
        -H "Authorization: Bearer ${GITHUB_TOKEN_RESOLVED}" \
        "https://api.github.com/user" 2>/dev/null); then
        login=$(echo "$api_response" | jq -r '.login // empty' 2>/dev/null || true)
        if [[ -n "$login" ]] && [[ "$login" != "null" ]]; then
            GITHUB_USER_RESOLVED="$login"
            log "GitHub user auto-detected from API: ${GITHUB_USER_RESOLVED}"
            return 0
        fi
    fi

    log "GitHub user: API auto-detect failed or returned no login — GITHUB_USER_RESOLVED remains empty"
    return 0
}

# ── GHCR API requests ─────────────────────────────────────────────────────────
# ghcr_api_request URL [SCOPE]
# Makes a GHCR v2 API call with OCI token exchange if a PAT is available.
# Falls back to unauthenticated on auth failure. Returns non-zero only if
# both authenticated and unauthenticated requests fail.
#
# Arguments:
#   URL   — the GHCR v2 API URL to request
#   SCOPE — optional OCI scope string (default: derived from URL path,
#            e.g. "repository:llm-api-proxy/server:pull")
#
# stdout: response body on success
# return: 0 on success (authenticated or unauthenticated fallback),
#         non-zero if both paths fail
ghcr_api_request() {
    local url="$1"
    local scope="${2:-}"

    # Derive scope from URL if not provided
    # e.g. https://ghcr.io/v2/llm-api-proxy/server/tags/list
    #   -> repository:llm-api-proxy/server:pull
    if [[ -z "$scope" ]]; then
        local path
        path=$(echo "$url" | sed -E 's|https?://ghcr.io/v2/([^/]+/[^/]+)/.*|\1|')
        scope="repository:${path}:pull"
    fi

    if [[ -n "${GITHUB_TOKEN_RESOLVED:-}" ]]; then
        # Exchange PAT for bearer token via GHCR token endpoint.
        # SECURITY: pass credentials via a temp config file so the PAT never
        # appears in curl argv (visible in ps output). The placeholder username
        # "token" is required by the GHCR token endpoint protocol; the actual
        # PAT is the password. GITHUB_USER_RESOLVED is intentionally NOT used here.
        local auth_config bearer token_response
        auth_config=$(mktemp)
        CLEANUP_FILES+=("$auth_config")
        printf 'user = "token:%s"\n' "$GITHUB_TOKEN_RESOLVED" > "$auth_config"
        chmod 0600 "$auth_config"

        local token_url="https://ghcr.io/token?service=ghcr.io&scope=${scope}"
        if token_response=$(curl -fsSL --max-time 10 -K "$auth_config" "$token_url" 2>/dev/null); then
            bearer=$(echo "$token_response" | jq -r '.token // empty' 2>/dev/null || true)
            rm -f "$auth_config"
            CLEANUP_FILES=("${CLEANUP_FILES[@]/$auth_config}")

            if [[ -n "$bearer" ]]; then
                local response
                if response=$(curl -fsSL --max-time 10 \
                    -H "Authorization: Bearer ${bearer}" \
                    "$url" 2>/dev/null); then
                    echo "$response"
                    return 0
                fi
                warn "Authenticated GHCR request failed for ${url}. Retrying unauthenticated."
            fi
        else
            rm -f "$auth_config"
            CLEANUP_FILES=("${CLEANUP_FILES[@]/$auth_config}")
            warn "GHCR token exchange failed. Token may be invalid, expired, or missing read:packages scope. Retrying unauthenticated."
        fi
    fi

    # Unauthenticated fallback
    local response
    if response=$(curl -fsSL --max-time 10 "$url" 2>/dev/null); then
        echo "$response"
        return 0
    fi

    return 1
}

# ── GHCR docker login ─────────────────────────────────────────────────────────
# Authenticates to GHCR via docker login before image pulls.
# Skips silently if no token. Warns and falls back gracefully on failure.
#
# Uses GITHUB_TOKEN_RESOLVED and GITHUB_USER_RESOLVED (set by resolve_github_token
# and detect_github_user respectively).
#
# Does NOT call docker logout — credentials are left in place for future
# upgrade runs.
#
# return: always 0 (failure is non-fatal; Docker will report pull errors)
ghcr_login() {
    if [[ -z "${GITHUB_TOKEN_RESOLVED:-}" ]]; then
        return 0
    fi

    if [[ -z "${GITHUB_USER_RESOLVED:-}" ]]; then
        warn "GitHub token set but username not available. Skipping docker login. Set --github-user= or GITHUB_USER to enable authenticated pulls."
        return 0
    fi

    local login_output
    if login_output=$(echo "$GITHUB_TOKEN_RESOLVED" | \
        $SUDO docker login ghcr.io -u "$GITHUB_USER_RESOLVED" --password-stdin 2>&1); then
        info "Authenticated to ghcr.io as ${GITHUB_USER_RESOLVED}"
    else
        warn "docker login ghcr.io failed: ${login_output}. Proceeding without authentication."
    fi
    return 0
}

# ── Setting resolution with 4-tier precedence ───────────────────────────────
# Usage: value=$(resolve_setting "OPT_DOMAIN" "DOMAIN" "Enter your domain" "proxy.example.com")
#   $1 = OPT_* variable name (already set by CLI or env)
#   $2 = .env key name to check in existing install
#   $3 = prompt text for interactive mode
#   $4 = default value (optional)
resolve_setting() {
    local opt_var="$1" env_key="$2" prompt_text="$3" default="${4:-}"
    local current_value="${!opt_var:-}"

    # 1. CLI flag or env var already set — use it
    if [[ -n "$current_value" ]]; then
        echo "$current_value"
        return 0
    fi

    # 2. Existing .env from previous installation
    if $SUDO test -f "${INSTALL_DIR:-}/docker/.env" 2>/dev/null; then
        local env_value
        env_value=$($SUDO grep "^${env_key}=" "${INSTALL_DIR}/docker/.env" 2>/dev/null | cut -d= -f2- || true)
        if [[ -n "$env_value" ]]; then
            echo "$env_value"
            return 0
        fi
    fi

    # 3. Interactive prompt
    if [[ "$OPT_NON_INTERACTIVE" == "true" ]]; then
        if [[ -n "$default" ]]; then
            echo "$default"
            return 0
        fi
        die "Required setting missing: ${prompt_text}. Provide via --${opt_var,,} or PROXY_INSTALL_${env_key}."
    fi

    ask_input "Configuration" "$prompt_text" "$default"
}

# ── Integrity verification ───────────────────────────────────────────────────

verify_self_checksum() {
    local script="${SCRIPT_PATH:-$0}"
    step "Verifying installer integrity..."

    # When run via `curl | bash`, $0 is "bash" — not a readable file on disk.
    # Transport integrity is guaranteed by the HTTPS download; skip the
    # file-based checksum check.
    if [[ ! -f "$script" ]]; then
        info "Running from pipe — skipping file integrity check (HTTPS provides transport security)"
        return 0
    fi

    local payload
    payload=$(awk '/^# --- BEGIN EMBEDDED FILES ---$/,/^# --- END EMBEDDED FILES ---$/' "$script" \
        | grep -v '^# SELF_CHECKSUM:')
    local computed
    computed=$(echo "$payload" | sha256sum | awk '{print $1}')

    local embedded
    embedded=$(grep '^# SELF_CHECKSUM:' "$script" | awk '{print $3}')

    if [[ -z "$embedded" ]] || [[ "$embedded" == "@@SELF_CHECKSUM@@" ]]; then
        warn "No self-checksum embedded (development build) — skipping"
        return 0
    fi

    if [[ "$computed" != "$embedded" ]]; then
        die "Installer integrity check failed. File may be corrupted or tampered with. Re-download from the official source."
    fi
    info "Self-checksum verified"
}

verify_remote_checksum() {
    if [[ "$OPT_SKIP_CHECKSUM" == "true" ]]; then
        info "Remote checksum verification skipped (--skip-checksum)"
        return 0
    fi

    if ! command -v curl &>/dev/null; then
        warn "curl not available — skipping remote checksum verification"
        return 0
    fi

    local version="${INSTALLER_VERSION}"
    local checksums_url="https://llm-api-proxy.com/.well-known/install-checksums/${version}/SHA256SUMS"

    local remote_checksums
    if ! remote_checksums=$(curl -fsSL --max-time 10 "$checksums_url" 2>/dev/null); then
        warn "Could not fetch remote checksums from ${checksums_url}"
        if [[ "$OPT_NON_INTERACTIVE" == "true" ]]; then
            warn "Continuing without remote verification (non-interactive)"
            return 0
        fi
        if ask_yesno "Checksum Warning" "Could not verify installer against published checksums. Continue anyway?" "no"; then
            return 0
        fi
        die "Remote checksum verification failed. Re-download the installer."
    fi

    local script="${SCRIPT_PATH:-$0}"
    # When run via `curl | bash`, there is no local file to hash.
    if [[ ! -f "$script" ]]; then
        info "Running from pipe — skipping remote checksum verification (HTTPS provides transport security)"
        return 0
    fi
    local local_hash
    local_hash=$(sha256sum "$script" | awk '{print $1}')

    if echo "$remote_checksums" | grep -q "$local_hash"; then
        info "Remote checksum verified"
    else
        die "Installer does not match published checksum. It may have been tampered with."
    fi
}

verify_gpg_signature() {
    if [[ "$OPT_SKIP_CHECKSUM" == "true" ]]; then
        return 0
    fi

    local gpg_cmd=""
    if command -v gpgv &>/dev/null; then
        gpg_cmd="gpgv"
    elif command -v gpg &>/dev/null; then
        gpg_cmd="gpg"
    else
        info "GPG not available — skipping signature verification"
        return 0
    fi

    local version="${INSTALLER_VERSION}"
    local sig_url="https://llm-api-proxy.com/.well-known/install-checksums/${version}/SHA256SUMS.sig"
    local checksums_url="https://llm-api-proxy.com/.well-known/install-checksums/${version}/SHA256SUMS"

    local sig_file checksums_file keyring_file
    sig_file=$(mktemp); CLEANUP_FILES+=("$sig_file")
    checksums_file=$(mktemp); CLEANUP_FILES+=("$checksums_file")
    keyring_file=$(mktemp); CLEANUP_FILES+=("$keyring_file")

    if ! curl -fsSL --max-time 10 "$sig_url" -o "$sig_file" 2>/dev/null; then
        warn "Could not fetch GPG signature — skipping"
        return 0
    fi
    if ! curl -fsSL --max-time 10 "$checksums_url" -o "$checksums_file" 2>/dev/null; then
        warn "Could not fetch checksums for GPG verification — skipping"
        return 0
    fi

    # Guard: if the server returned HTML (e.g. SPA fallback) instead of real
    # signature/checksum files, skip gracefully rather than failing gpgv.
    if head -1 "$sig_file" | grep -qi '<!doctype\|<html'; then
        warn "Signature endpoint returned HTML instead of a signature — skipping GPG verification"
        return 0
    fi
    if head -1 "$checksums_file" | grep -qi '<!doctype\|<html'; then
        warn "Checksums endpoint returned HTML instead of checksums — skipping GPG verification"
        return 0
    fi

    if [[ -n "${EMBED_gpg_public_key:-}" ]]; then
        echo "$EMBED_gpg_public_key" | base64 -d > "$keyring_file"
    else
        warn "No GPG public key embedded — skipping signature verification"
        return 0
    fi

    # Guard: if the embedded key is a placeholder (not a real GPG key), skip.
    if ! grep -q 'BEGIN PGP' "$keyring_file" 2>/dev/null; then
        warn "Embedded GPG key is not a valid PGP key — skipping signature verification"
        return 0
    fi

    if [[ "$gpg_cmd" == "gpgv" ]]; then
        if gpgv --keyring "$keyring_file" "$sig_file" "$checksums_file" 2>/dev/null; then
            info "GPG signature verified"
        else
            die "GPG signature verification failed. Installer may have been tampered with."
        fi
    else
        local tmpring
        tmpring=$(mktemp -d); CLEANUP_FILES+=("$tmpring")
        gpg --homedir "$tmpring" --import "$keyring_file" 2>/dev/null
        if gpg --homedir "$tmpring" --verify "$sig_file" "$checksums_file" 2>/dev/null; then
            info "GPG signature verified"
        else
            die "GPG signature verification failed. Installer may have been tampered with."
        fi
    fi
}

# ── Platform detection ───────────────────────────────────────────────────────

# shellcheck disable=SC2034  # OS_ID, OS_VERSION, OS_CODENAME, PKG_MANAGER, ARCH, IS_MACOS,
# INSTALL_DIR, METADATA_DIR, PREFLIGHT_*, EXISTING_INSTALL are read by phase functions
# appended by build-installer.sh
OS_ID=""
OS_VERSION=""
OS_CODENAME=""
PKG_MANAGER=""
ARCH=""
IS_MACOS="false"
INSTALL_DIR=""
METADATA_DIR=""
PREFLIGHT_PASS=()
PREFLIGHT_WARN=()
PREFLIGHT_FAIL=()
PREFLIGHT_INFO=()

# macOS Docker Desktop host-networking state (set by detect_docker_desktop_version
# and enable_docker_desktop_host_networking).
# shellcheck disable=SC2034  # Read by deploy_extract_files and deploy_write_compose_command
MACOS_HOST_NETWORKING="false"
DOCKER_DESKTOP_VERSION=""
DOCKER_DESKTOP_HOST_NET_CAPABLE="false"

detect_os() {
    if [[ "$(uname -s)" == "Darwin" ]]; then
        IS_MACOS="true"
        OS_ID="macos"
        OS_VERSION=$(sw_vers -productVersion 2>/dev/null || echo "unknown")
        PKG_MANAGER="brew"
        INSTALL_DIR="${OPT_INSTALL_DIR:-$INSTALL_DIR_MACOS}"
        # shellcheck disable=SC2034  # METADATA_DIR used by phase functions appended by build-installer.sh
        METADATA_DIR="$METADATA_DIR_MACOS"
        # mDNS is always disabled on macOS — Docker Desktop's host networking is
        # layer-4 only (TCP/UDP). Multicast does not cross the Docker Desktop VM
        # boundary regardless of whether host networking is enabled.
        # shellcheck disable=SC2034  # OPT_MDNS used by phase functions appended by build-installer.sh
        OPT_MDNS="false"
        return 0
    fi

    INSTALL_DIR="${OPT_INSTALL_DIR:-$INSTALL_DIR_LINUX}"
    # shellcheck disable=SC2034  # METADATA_DIR used by phase functions appended by build-installer.sh
    METADATA_DIR="$METADATA_DIR_LINUX"

    if [[ ! -f /etc/os-release ]]; then
        die "Cannot detect OS — /etc/os-release not found. Supported: Debian, Ubuntu, RHEL, Fedora, Arch, openSUSE."
    fi

    # shellcheck source=/dev/null
    source /etc/os-release 2>/dev/null || true
    OS_ID="${ID:-unknown}"
    OS_VERSION="${VERSION_ID:-unknown}"
    OS_CODENAME="${VERSION_CODENAME:-}"

    case "$OS_ID" in
        debian|ubuntu)     PKG_MANAGER="apt" ;;
        rhel|centos|rocky|almalinux|fedora)
                           PKG_MANAGER="dnf"
                           command -v dnf &>/dev/null || PKG_MANAGER="yum" ;;
        arch|manjaro)      PKG_MANAGER="pacman" ;;
        opensuse*|sles)    PKG_MANAGER="zypper" ;;
        *)
            warn "Unrecognized OS: ${OS_ID}. Proceeding as best-effort."
            PKG_MANAGER="unknown" ;;
    esac
    log "Detected OS: ${OS_ID} ${OS_VERSION} (${OS_CODENAME:-n/a}), pkg: ${PKG_MANAGER}"
}

detect_arch() {
    local raw_arch
    raw_arch=$(uname -m)
    case "$raw_arch" in
        x86_64|amd64)   ARCH="amd64" ;;
        aarch64|arm64)   ARCH="arm64" ;;
        *)               die "Unsupported architecture: $raw_arch. Supported: amd64, arm64." ;;
    esac
    log "Detected arch: ${ARCH}"
}

detect_virtualization() {
    local virt="bare-metal"
    if command -v systemd-detect-virt &>/dev/null; then
        virt=$(systemd-detect-virt 2>/dev/null || echo "bare-metal")
    elif [[ -f /proc/cpuinfo ]]; then
        grep -qi "hypervisor" /proc/cpuinfo && virt="vm"
    fi
    PREFLIGHT_INFO+=("Virtualization: ${virt}")
    log "Virtualization: ${virt}"
}

# ── Docker Desktop host-networking detection (macOS only) ────────────────────

# Returns the path to Docker Desktop's Info.plist.
# Checks system /Applications first, then user ~/Applications.
# Returns 1 if Docker.app is not found in either location.
# This function is mockable in tests via `export -f _docker_desktop_plist_path`.
_docker_desktop_plist_path() {
    local system_path="/Applications/Docker.app/Contents/Info.plist"
    local user_path="${HOME}/Applications/Docker.app/Contents/Info.plist"
    if [[ -f "$system_path" ]]; then
        echo "$system_path"
    elif [[ -f "$user_path" ]]; then
        echo "$user_path"
    else
        return 1
    fi
}

# Detects the Docker Desktop version from Info.plist and sets:
#   DOCKER_DESKTOP_VERSION          — raw version string (e.g. "4.34.0")
#   DOCKER_DESKTOP_HOST_NET_CAPABLE — "true" if version ≥ 4.34, "false" otherwise
#
# Calls _docker_desktop_plist_path() (mockable in tests) to locate the plist.
# If the plist cannot be found or parsed, capability is set to "false" (safe default).
detect_docker_desktop_version() {
    local plist_path="" version="" major="" minor=""

    # Get plist path — this function is mockable in tests
    if plist_path=$(_docker_desktop_plist_path 2>/dev/null) && [[ -f "$plist_path" ]]; then
        # Parse CFBundleShortVersionString — handle text plist format.
        # Use || true so grep non-match (exit 1) does not abort under set -e.
        version=$(grep -A1 'CFBundleShortVersionString' "$plist_path" 2>/dev/null | \
            grep -o '[0-9][0-9]*\.[0-9][0-9]*\.[0-9][0-9]*' 2>/dev/null | head -1 || true)
        if [[ -z "$version" ]]; then
            # Try PlistBuddy for binary plist
            version=$(/usr/libexec/PlistBuddy -c "Print CFBundleShortVersionString" "$plist_path" 2>/dev/null | \
                grep -o '[0-9][0-9]*\.[0-9][0-9]*\.[0-9][0-9]*' 2>/dev/null | head -1 || true)
        fi
    fi

    # Note: do NOT fall back to `docker version` here — the Docker engine version
    # is not the same as Docker Desktop version. If the plist is absent, we cannot
    # determine DD version and must treat it as not capable.

    DOCKER_DESKTOP_VERSION="${version:-}"

    if [[ -z "$version" ]]; then
        DOCKER_DESKTOP_HOST_NET_CAPABLE="false"
        return 0
    fi

    # Compare major.minor — extract just first two components
    major=$(echo "$version" | cut -d. -f1)
    minor=$(echo "$version" | cut -d. -f2)

    # ≥4.34 means major>4 OR (major=4 AND minor>=34)
    if [[ "$major" -gt 4 ]] || { [[ "$major" -eq 4 ]] && [[ "$minor" -ge 34 ]]; }; then
        DOCKER_DESKTOP_HOST_NET_CAPABLE="true"
    else
        DOCKER_DESKTOP_HOST_NET_CAPABLE="false"
    fi
}

# Verifies that Docker Desktop prerequisites for host networking are met:
#   1. DOCKER_DESKTOP_HOST_NET_CAPABLE must be "true"
#   2. Docker must be in Linux containers mode
#   3. Enhanced Container Isolation (ECI) must not be enabled
# Returns 0 if all prerequisites pass, 1 otherwise.
check_docker_desktop_host_net_prerequisites() {
    # Must have been detected as capable first
    if [[ "$DOCKER_DESKTOP_HOST_NET_CAPABLE" != "true" ]]; then
        return 1
    fi

    # Capture docker info output once — the mock in tests only handles `docker info`
    # (not `docker info --format`), so we parse raw output ourselves.
    local docker_info
    docker_info=$(docker info 2>/dev/null)

    # First line should be the OS type (linux / windows / darwin)
    local os_type
    os_type=$(echo "$docker_info" | head -1)
    if [[ "$os_type" != "linux" ]]; then
        warn "Docker Desktop is not in Linux containers mode (got: ${os_type:-unknown})"
        return 1
    fi

    # Must NOT have Enhanced Container Isolation enabled
    if echo "$docker_info" | grep -qi "Enhanced Container Isolation.*true"; then
        warn "Enhanced Container Isolation (ECI) is enabled — incompatible with host networking"
        return 1
    fi

    return 0
}

# Runs a Docker container with --network=host to verify host networking works.
# Returns 0 if host networking is functional, 1 otherwise.
check_docker_host_networking() {
    docker run --rm --network=host alpine:latest \
        sh -c 'ip -6 addr show lo 2>/dev/null | grep -q inet6' 2>/dev/null
}

# Enables Docker Desktop host networking on macOS (DD 4.34+).
# Sets MACOS_HOST_NETWORKING="true" if host networking is confirmed working.
# Returns 0 on success, 1 if host networking could not be enabled or verified.
enable_docker_desktop_host_networking() {
    if [[ "$DOCKER_DESKTOP_HOST_NET_CAPABLE" != "true" ]]; then
        return 1
    fi

    # Check if host networking is already enabled via smoke test
    if check_docker_host_networking; then
        MACOS_HOST_NETWORKING="true"
        return 0
    fi

    # Non-interactive mode: skip guided enablement
    if [[ "${OPT_NON_INTERACTIVE:-false}" == "true" ]]; then
        warn "Host networking not enabled — using bridge networking (non-interactive mode)"
        return 1
    fi

    # Guided manual enablement
    echo ""
    echo "  Docker Desktop ${DOCKER_DESKTOP_VERSION} supports host networking,"
    echo "  which preserves real client source IPs and improves performance."
    echo ""
    echo "  To enable it:"
    echo "    1. Open Docker Desktop → Settings → Resources → Network"
    echo "    2. Enable 'Enable host networking'"
    echo "    3. Click 'Apply & restart'"
    echo ""
    echo "  ⚠  Restarting Docker Desktop will stop all running containers."
    echo ""
    read -r -p "  Press Enter after enabling host networking in Docker Desktop..."

    # Wait for Docker Desktop to come back
    local attempts=0
    while ! docker info &>/dev/null; do
        attempts=$((attempts + 1))
        if [[ $attempts -ge 30 ]]; then
            warn "Docker Desktop not responding after restart — using bridge networking"
            return 1
        fi
        sleep 2
    done

    # Verify host networking actually works
    if check_docker_host_networking; then
        MACOS_HOST_NETWORKING="true"
        info "Host networking enabled and verified"
        return 0
    else
        warn "Host networking could not be verified — using bridge networking"
        return 1
    fi
}

check_root() {
    if [[ "$IS_MACOS" == "true" ]]; then
        return 0
    fi
    if [[ $EUID -eq 0 ]]; then
        PREFLIGHT_PASS+=("Root access: running as root")
    elif sudo -n true 2>/dev/null; then
        PREFLIGHT_PASS+=("Root access: sudo available")
    else
        PREFLIGHT_FAIL+=("Root access required — run with: curl -fsSL .../install.sh | sudo bash")
    fi
}

check_ipv6() {
    if [[ "$IS_MACOS" == "true" ]]; then
        PREFLIGHT_PASS+=("IPv6: available (macOS)")
        return 0
    fi
    if [[ -f /proc/sys/net/ipv6/conf/all/disable_ipv6 ]]; then
        local disabled
        disabled=$(cat /proc/sys/net/ipv6/conf/all/disable_ipv6)
        if [[ "$disabled" == "1" ]]; then
            PREFLIGHT_FAIL+=("IPv6: disabled in kernel")
            PREFLIGHT_FAIL+=("  → Enable: sysctl -w net.ipv6.conf.all.disable_ipv6=0")
        else
            PREFLIGHT_PASS+=("IPv6: enabled")
        fi
    elif [[ -d /proc/sys/net/ipv6 ]]; then
        PREFLIGHT_PASS+=("IPv6: kernel support available")
    else
        PREFLIGHT_FAIL+=("IPv6: not available in kernel")
        PREFLIGHT_FAIL+=("  → Rebuild kernel with CONFIG_IPV6=y or load ipv6 module")
    fi
}

_get_total_ram_kb() {
    if [[ "$IS_MACOS" == "true" ]]; then
        sysctl -n hw.memsize 2>/dev/null | awk '{print int($1/1024)}'
    else
        grep MemTotal /proc/meminfo 2>/dev/null | awk '{print $2}'
    fi
}

check_ram() {
    local total_kb
    total_kb=$(_get_total_ram_kb)
    local total_mb=$((total_kb / 1024))
    local total_gb=$((total_mb / 1024))

    PREFLIGHT_INFO+=("RAM: ${total_mb} MB (${total_gb} GB)")

    if [[ $total_kb -lt 2097152 ]]; then
        PREFLIGHT_FAIL+=("RAM: ${total_mb} MB — minimum 2 GB required")
        return 1
    elif [[ $total_kb -lt 4194304 ]]; then
        PREFLIGHT_WARN+=("RAM: ${total_mb} MB — 4+ GB recommended for production")
    else
        PREFLIGHT_PASS+=("RAM: ${total_mb} MB (minimum 2 GB)")
    fi
    return 0
}

_get_free_disk_kb() {
    df -k "$1" 2>/dev/null | tail -1 | awk '{print $4}'
}

check_disk() {
    local path="${1:-$INSTALL_DIR}"
    local check_path="$path"
    while [[ ! -d "$check_path" ]] && [[ "$check_path" != "/" ]]; do
        check_path=$(dirname "$check_path")
    done

    local free_kb
    free_kb=$(_get_free_disk_kb "$check_path")
    local free_gb=$((free_kb / 1024 / 1024))

    PREFLIGHT_INFO+=("Disk: ${free_gb} GB free at ${path}")

    if [[ $free_kb -lt 10485760 ]]; then
        PREFLIGHT_FAIL+=("Disk: ${free_gb} GB free — minimum 10 GB required at ${path}")
        return 1
    else
        PREFLIGHT_PASS+=("Disk: ${free_gb} GB free (minimum 10 GB)")
    fi
    return 0
}

check_ports() {
    local -a public_ports=(443 8443)
    local -a localhost_ports=(7080 7443 5432 8500 8180 3000 9090 5353)

    if ! command -v ss &>/dev/null && ! command -v lsof &>/dev/null; then
        PREFLIGHT_WARN+=("Port check: ss/lsof not available — skipping")
        return 0
    fi

    local port proc
    for port in "${public_ports[@]}" "${localhost_ports[@]}"; do
        proc=""
        if command -v ss &>/dev/null; then
            proc=$(ss -tlnp "sport = :${port}" 2>/dev/null | grep -v "^State" | head -1 || true)
        elif command -v lsof &>/dev/null; then
            proc=$(lsof -iTCP:"${port}" -sTCP:LISTEN -P -n 2>/dev/null | tail -1 || true)
        fi
        if [[ -n "$proc" ]]; then
            PREFLIGHT_WARN+=("Port ${port}: in use — ${proc}")
        fi
    done
}

check_docker() {
    if ! command -v docker &>/dev/null; then
        PREFLIGHT_INFO+=("Docker: not installed (will install)")
        return 0
    fi

    local docker_version
    docker_version=$(docker --version 2>/dev/null || echo "unknown")
    PREFLIGHT_INFO+=("Docker: ${docker_version}")

    if docker --version 2>/dev/null | grep -qi "docker.io"; then
        PREFLIGHT_WARN+=("Docker: distro package (docker.io) — official docker-ce recommended")
    fi

    if ! docker compose version &>/dev/null; then
        PREFLIGHT_WARN+=("Docker Compose plugin not found (will install)")
    else
        local compose_version
        compose_version=$(docker compose version --short 2>/dev/null || echo "unknown")
        PREFLIGHT_INFO+=("Docker Compose: ${compose_version}")
    fi
}

check_container() {
    if [[ -f /proc/1/environ ]] && grep -qai "container=lxc" /proc/1/environ 2>/dev/null; then
        PREFLIGHT_FAIL+=("Running inside LXC container — Docker-in-container not supported")
    fi
    if [[ -d /proc/vz ]] && [[ ! -d /proc/bc ]]; then
        PREFLIGHT_FAIL+=("Running inside OpenVZ container — Docker-in-container not supported")
    fi
}

check_internet() {
    local -a hosts=("ghcr.io")
    local host
    for host in "${hosts[@]}"; do
        if ! curl -fsSL --max-time 5 "https://${host}" -o /dev/null 2>/dev/null; then
            if ! ping -c1 -W3 "$host" &>/dev/null; then
                PREFLIGHT_FAIL+=("Cannot reach ${host} — internet connectivity required")
            fi
        fi
    done
}

detect_existing_install() {
    local -a search_paths=(
        "/etc/llm-api-proxy/install.json"
        "${HOME}/.config/llm-api-proxy/install.json"
    )
    if [[ -n "${OPT_INSTALL_DIR:-}" ]]; then
        search_paths=("${OPT_INSTALL_DIR}/install.json" "${search_paths[@]}")
    fi

    local p
    for p in "${search_paths[@]}"; do
        # Use $SUDO for the file test so detection works when the script is
        # run as a non-root user (install.json is typically owned by root).
        if $SUDO test -f "$p" 2>/dev/null; then
            EXISTING_INSTALL="$p"
            local existing_version
            existing_version=$($SUDO jq -r '.version // "unknown"' "$p" 2>/dev/null || echo "unknown")
            local existing_dir
            existing_dir=$($SUDO jq -r '.install_dir // "unknown"' "$p" 2>/dev/null || echo "unknown")
            PREFLIGHT_INFO+=("Existing install: v${existing_version} at ${existing_dir}")
            return 0
        fi
    done
    EXISTING_INSTALL=""
}

# Validate GHCR access to private debug container images.
# Called from run_preflight() when OPT_DEBUG=true.
# Probes server-debug (always) and backup-debug (when OPT_BACKUP=true).
# Gracefully skips the probe if jq is not available.
preflight_debug_registry() {
    [[ "$OPT_DEBUG" == "true" ]] || return 0

    # Graceful degradation: skip probe if jq unavailable
    if ! command -v jq &>/dev/null; then
        warn "jq not available — skipping GHCR debug registry preflight probe"
        return 0
    fi

    # Token is required for private debug images
    if [[ -z "${GITHUB_TOKEN_RESOLVED:-}" ]]; then
        die "Debug containers require a GitHub PAT with package:read access. Provide it via --github-token=, PROXY_INSTALL_GITHUB_TOKEN, CR_PAT, GH_TOKEN, or GITHUB_TOKEN."
    fi

    step "  Checking GHCR debug container access..."

    # Probe server-debug
    local server_url="https://ghcr.io/v2/llm-api-proxy/server-debug/tags/list"
    local server_scope="repository:llm-api-proxy/server-debug:pull"
    if ! ghcr_api_request "$server_url" "$server_scope" &>/dev/null; then
        die "Cannot access GHCR package 'server-debug'. Check your token has package:read access to llm-api-proxy/server-debug."
    fi

    # Probe backup-debug only when backups are enabled
    if [[ "$OPT_BACKUP" == "true" ]]; then
        local backup_url="https://ghcr.io/v2/llm-api-proxy/backup-debug/tags/list"
        local backup_scope="repository:llm-api-proxy/backup-debug:pull"
        if ! ghcr_api_request "$backup_url" "$backup_scope" &>/dev/null; then
            die "Cannot access GHCR package 'backup-debug'. Check your token has package:read access to llm-api-proxy/backup-debug."
        fi
    fi

    info "Debug container registry accessible"
}

run_preflight() {
    step "[1/5] Running preflight checks..."
    PREFLIGHT_PASS=()
    PREFLIGHT_WARN=()
    PREFLIGHT_FAIL=()
    PREFLIGHT_INFO=()
    # shellcheck disable=SC2034  # EXISTING_INSTALL used by phase functions appended by build-installer.sh
    EXISTING_INSTALL=""

    preflight_debug_registry

    verify_self_checksum
    verify_remote_checksum
    verify_gpg_signature

    PREFLIGHT_INFO+=("OS: ${OS_ID} ${OS_VERSION} (${ARCH})")
    check_root
    check_ipv6
    check_ram || true
    check_disk "$INSTALL_DIR" || true
    check_container
    check_internet
    check_ports
    check_docker
    detect_virtualization
    detect_existing_install

    local lines=()
    local item
    for item in "${PREFLIGHT_PASS[@]}"; do lines+=("✓ ${item}"); done
    for item in "${PREFLIGHT_WARN[@]}"; do lines+=("⚠ ${item}"); done
    for item in "${PREFLIGHT_FAIL[@]}"; do lines+=("✗ ${item}"); done
    for item in "${PREFLIGHT_INFO[@]}"; do lines+=("  ${item}"); done

    draw_box "Preflight Check Results" "${lines[@]}"

    if [[ ${#PREFLIGHT_FAIL[@]} -gt 0 ]]; then
        echo ""
        echo "${#PREFLIGHT_FAIL[@]} critical failure(s) — cannot proceed."
        echo "Fix the issues above and re-run."
        exit 1
    fi

    if [[ ${#PREFLIGHT_WARN[@]} -gt 0 ]]; then
        if [[ "$OPT_NON_INTERACTIVE" == "true" ]]; then
            warn "${#PREFLIGHT_WARN[@]} warning(s) — continuing (non-interactive)"
        else
            if ! ask_yesno "Preflight Warnings" "${#PREFLIGHT_WARN[@]} warning(s) found. Continue anyway?" "yes"; then
                die "Aborted by user."
            fi
        fi
    fi

    info "Preflight checks passed"
}

# ── Phase 2: Legal / Terms of Service ────────────────────────────────────────

# shellcheck disable=SC2034  # Used by deploy_write_metadata and main
TOS_URL="https://llm-api-proxy.com/legal/terms"
# shellcheck disable=SC2034
TOS_CONTENT=""
# shellcheck disable=SC2034
TOS_SHA256=""
# shellcheck disable=SC2034
TOS_VERSION=""
# shellcheck disable=SC2034
TOS_ACCEPTED_AT=""

fetch_tos() {
    local fetched
    if fetched=$(curl -fsSL --max-time 15 "$TOS_URL" 2>/dev/null); then
        # Guard: SPA fallback returns HTML instead of plain-text terms
        if printf '%s' "$fetched" | head -1 | grep -qi '<!doctype\|<html'; then
            log "ToS endpoint returned HTML (SPA fallback) — treating as fetch failure"
        else
            TOS_CONTENT="$fetched"
            TOS_SHA256=$(printf '%s' "$TOS_CONTENT" | sha256sum | awk '{print $1}')
            log "Fetched ToS from ${TOS_URL} (sha256: ${TOS_SHA256:0:12}...)"
            return 0
        fi
    fi

    if [[ -n "${EMBED_tos_text:-}" ]]; then
        TOS_CONTENT=$(printf '%s' "$EMBED_tos_text" | base64 -d)
        TOS_SHA256=$(printf '%s' "$TOS_CONTENT" | sha256sum | awk '{print $1}')
        warn "Could not fetch latest Terms of Service."
        warn "Showing embedded version. Current terms may have changed —"
        warn "review at ${TOS_URL} when online."
        return 0
    fi

    # No plain-text terms available — use a reference notice instead.
    warn "Could not fetch Terms of Service text."
    TOS_CONTENT="$(cat <<TERMS_NOTICE
LLAP Terms of Service

The full Terms of Service are available at:
  ${TOS_URL}

By proceeding with installation you confirm that you have read and
accept the Terms of Service published at the URL above.
TERMS_NOTICE
)"
    TOS_SHA256=$(printf '%s' "$TOS_CONTENT" | sha256sum | awk '{print $1}')
    return 0
}

display_tos() {
    local tos_file
    tos_file=$(mktemp); CLEANUP_FILES+=("$tos_file")
    printf '%s\n' "$TOS_CONTENT" > "$tos_file"

    if [[ -n "$DIALOG_CMD" ]] && [[ -t 0 ]]; then
        "$DIALOG_CMD" --title "Terms of Service" --textbox "$tos_file" 24 78
    elif command -v less &>/dev/null && [[ -t 0 ]]; then
        less "$tos_file"
    else
        echo "═══ Terms of Service ═══"
        printf '%s\n' "$TOS_CONTENT"
        echo "════════════════════════"
    fi
}

run_tos() {
    step "[2/5] Terms of Service"

    if [[ "$OPT_NON_INTERACTIVE" == "true" ]]; then
        if [[ "$OPT_ACCEPT_TOS" != "true" ]]; then
            die "Terms of Service acceptance required. Pass --accept-tos to accept."
        fi
        fetch_tos
        # shellcheck disable=SC2034  # Consumed by deploy_write_metadata
        TOS_ACCEPTED_AT=$(date -u +%Y-%m-%dT%H:%M:%SZ)
        info "Terms of Service accepted (non-interactive by $(whoami))"
        return 0
    fi

    # If --accept-tos was passed, skip display and accept immediately
    if [[ "$OPT_ACCEPT_TOS" == "true" ]]; then
        fetch_tos
        # shellcheck disable=SC2034
        TOS_ACCEPTED_AT=$(date -u +%Y-%m-%dT%H:%M:%SZ)
        info "Terms of Service accepted (--accept-tos flag)"
        return 0
    fi

    fetch_tos
    display_tos

    # When stdin is not a tty (curl | bash), interactive prompts are impossible.
    # Proceeding with installation implies acceptance — print the notice and continue.
    if [[ ! -t 0 ]]; then
        info "Terms of Service accepted (proceeding with installation implies acceptance)"
        # shellcheck disable=SC2034
        TOS_ACCEPTED_AT=$(date -u +%Y-%m-%dT%H:%M:%SZ)
        return 0
    fi

    if ! ask_yesno "Terms of Service" "Do you accept the Terms of Service?" "no"; then
        die "You must accept the Terms of Service to install or upgrade llm-api-proxy."
    fi

    # shellcheck disable=SC2034  # Consumed by deploy_write_metadata
    TOS_ACCEPTED_AT=$(date -u +%Y-%m-%dT%H:%M:%SZ)
    info "Terms of Service accepted"
}

# ── Phase 3: Prepare (system modifications) ──────────────────────────────────

prepare_system_upgrade() {
    if [[ "$OPT_SKIP_SYSTEM_UPGRADE" == "true" ]]; then
        info "System package upgrade skipped (--skip-system-upgrade)"
        return 0
    fi

    if [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
        if ! ask_yesno "System Update" "Update all system packages before proceeding? (recommended)" "yes"; then
            info "System package upgrade skipped by user"
            return 0
        fi
    fi

    step "  Updating system packages..."
    case "$PKG_MANAGER" in
        apt)
            $SUDO apt-get update -qq >> "$LOG_FILE" 2>&1
            $SUDO env DEBIAN_FRONTEND=noninteractive apt-get upgrade -y -qq >> "$LOG_FILE" 2>&1
            ;;
        dnf)    $SUDO dnf upgrade -y -q >> "$LOG_FILE" 2>&1 ;;
        yum)    $SUDO yum update -y -q >> "$LOG_FILE" 2>&1 ;;
        pacman) $SUDO pacman -Syu --noconfirm >> "$LOG_FILE" 2>&1 ;;
        zypper) $SUDO zypper -n update >> "$LOG_FILE" 2>&1 ;;
        brew)   brew update >> "$LOG_FILE" 2>&1 && brew upgrade >> "$LOG_FILE" 2>&1 ;;
        *)      warn "Unknown package manager — skipping system upgrade" ;;
    esac
    info "System packages updated"
}

prepare_prerequisites() {
    step "  Installing prerequisites..."
    local -a pkgs=()

    case "$PKG_MANAGER" in
        apt)
            pkgs=(curl jq ca-certificates gnupg lsb-release)
            if ! command -v dialog &>/dev/null && ! command -v whiptail &>/dev/null; then
                pkgs+=(dialog)
            fi
            $SUDO apt-get update -qq >> "$LOG_FILE" 2>&1
            $SUDO env DEBIAN_FRONTEND=noninteractive apt-get install -y -qq "${pkgs[@]}" >> "$LOG_FILE" 2>&1
            ;;
        dnf|yum)
            pkgs=(curl jq ca-certificates gnupg2)
            command -v dialog &>/dev/null || pkgs+=(dialog)
            $SUDO "$PKG_MANAGER" install -y -q "${pkgs[@]}" >> "$LOG_FILE" 2>&1
            ;;
        pacman)
            pkgs=(curl jq ca-certificates gnupg)
            command -v dialog &>/dev/null || pkgs+=(dialog)
            $SUDO pacman -S --noconfirm --needed "${pkgs[@]}" >> "$LOG_FILE" 2>&1
            ;;
        zypper)
            pkgs=(curl jq ca-certificates gpg2)
            command -v dialog &>/dev/null || pkgs+=(dialog)
            $SUDO zypper -n install "${pkgs[@]}" >> "$LOG_FILE" 2>&1
            ;;
        brew)
            for pkg in curl jq gnupg; do
                brew list "$pkg" &>/dev/null || brew install "$pkg" >> "$LOG_FILE" 2>&1
            done
            ;;
    esac
    detect_dialog
    info "Prerequisites installed"
}

prepare_docker() {
    if command -v docker &>/dev/null; then
        if docker --version 2>/dev/null | grep -qi "docker.io"; then
            warn "Distro Docker package detected. Official docker-ce recommended."
            if [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
                if ask_yesno "Docker" "Replace distro Docker with official docker-ce?" "yes"; then
                    case "$PKG_MANAGER" in
                        apt) $SUDO apt-get remove -y docker.io docker-doc docker-compose >> "$LOG_FILE" 2>&1 ;;
                        dnf|yum) $SUDO "$PKG_MANAGER" remove -y docker docker-common >> "$LOG_FILE" 2>&1 ;;
                    esac
                else
                    info "Keeping existing Docker installation"
                    return 0
                fi
            fi
        else
            info "Docker already installed (official)"
            return 0
        fi
    fi

    step "  Installing Docker..."
    case "$PKG_MANAGER" in
        apt)
            $SUDO install -m 0755 -d /etc/apt/keyrings
            local repo_url="https://download.docker.com/linux/${OS_ID}"
            curl -fsSL "${repo_url}/gpg" | $SUDO gpg --dearmor -o /etc/apt/keyrings/docker.gpg >> "$LOG_FILE" 2>&1
            $SUDO chmod a+r /etc/apt/keyrings/docker.gpg
            echo "deb [arch=${ARCH} signed-by=/etc/apt/keyrings/docker.gpg] ${repo_url} ${OS_CODENAME} stable" \
                | $SUDO tee /etc/apt/sources.list.d/docker.list > /dev/null
            $SUDO apt-get update -qq >> "$LOG_FILE" 2>&1
            $SUDO env DEBIAN_FRONTEND=noninteractive apt-get install -y -qq \
                docker-ce docker-ce-cli containerd.io docker-compose-plugin >> "$LOG_FILE" 2>&1
            ;;
        dnf)
            local docker_repo="https://download.docker.com/linux/centos/docker-ce.repo"
            [[ "$OS_ID" == "fedora" ]] && docker_repo="https://download.docker.com/linux/fedora/docker-ce.repo"
            $SUDO dnf config-manager --add-repo "$docker_repo" >> "$LOG_FILE" 2>&1
            $SUDO dnf install -y docker-ce docker-ce-cli containerd.io docker-compose-plugin >> "$LOG_FILE" 2>&1
            ;;
        yum)
            $SUDO yum-config-manager --add-repo "https://download.docker.com/linux/centos/docker-ce.repo" >> "$LOG_FILE" 2>&1
            $SUDO yum install -y docker-ce docker-ce-cli containerd.io docker-compose-plugin >> "$LOG_FILE" 2>&1
            ;;
        pacman)
            $SUDO pacman -S --noconfirm docker docker-compose >> "$LOG_FILE" 2>&1
            ;;
        zypper)
            $SUDO zypper -n install docker docker-compose >> "$LOG_FILE" 2>&1 || {
                warn "Trying official Docker repo for openSUSE..."
                $SUDO zypper addrepo "https://download.docker.com/linux/sles/docker-ce.repo" >> "$LOG_FILE" 2>&1
                $SUDO zypper -n install docker-ce docker-ce-cli containerd.io docker-compose-plugin >> "$LOG_FILE" 2>&1
            }
            ;;
        brew)
            if [[ ! -d "/Applications/Docker.app" ]]; then
                brew install --cask docker >> "$LOG_FILE" 2>&1
                echo ""
                echo "  Docker Desktop installed. Please open Docker Desktop"
                echo "  from your Applications folder and wait for it to start."
                echo ""
                if [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
                    read -r -p "  Press Enter when Docker Desktop is running..."
                fi
            fi
            local attempts=0
            while ! docker info &>/dev/null; do
                attempts=$((attempts + 1))
                if [[ $attempts -ge 30 ]]; then
                    die "Docker Desktop not responding. Open it and re-run."
                fi
                sleep 2
            done
            info "Docker Desktop running"
            # Docker Desktop host networking (macOS only, DD 4.34+)
            detect_docker_desktop_version
            if check_docker_desktop_host_net_prerequisites; then
                enable_docker_desktop_host_networking
            fi
            return 0
            ;;
        *)
            die "Cannot install Docker automatically on ${OS_ID}. Install manually: https://docs.docker.com/engine/install/"
            ;;
    esac

    if [[ "$IS_MACOS" != "true" ]]; then
        $SUDO systemctl enable docker >> "$LOG_FILE" 2>&1
        $SUDO systemctl start docker >> "$LOG_FILE" 2>&1
    fi

    if ! $SUDO docker info &>/dev/null; then
        die "Docker installed but not responding. Check: systemctl status docker"
    fi
    info "Docker installed and running"
}

prepare_docker_ipv6() {
    step "  Configuring Docker IPv6..."

    if [[ "$IS_MACOS" == "true" ]]; then
        if $SUDO docker info --format '{{.IPv6Forwarding}}' 2>/dev/null | grep -qi "true"; then
            info "Docker IPv6 already enabled"
            return 0
        fi
        echo ""
        echo "  Docker Desktop requires manual IPv6 configuration:"
        echo "  Settings → Docker Engine → add to JSON:"
        echo '    "ipv6": true,'
        echo '    "fixed-cidr-v6": "fd00:d0c:1::/64"'
        echo ""
        if [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
            read -r -p "  Press Enter after enabling IPv6 in Docker Desktop..."
        fi
        return 0
    fi

    local daemon_json="/etc/docker/daemon.json"
    local existing="{}"
    if [[ -f "$daemon_json" ]]; then
        existing=$($SUDO cat "$daemon_json")
    fi

    if echo "$existing" | jq -e '.ipv6 == true' &>/dev/null; then
        info "Docker IPv6 already configured"
        return 0
    fi

    if [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
        if ! ask_yesno "Docker IPv6" "Enabling IPv6 requires restarting Docker (stops running containers). Proceed?" "yes"; then
            die "IPv6 is required. This project is IPv6-first. Please enable IPv6 and re-run."
        fi
    fi

    local merged
    merged=$(echo "$existing" | jq '. + {"ipv6":true,"fixed-cidr-v6":"fd00:d0c:1::/64","ip6tables":true}')
    local tmpfile
    tmpfile=$(mktemp); CLEANUP_FILES+=("$tmpfile")
    echo "$merged" > "$tmpfile"
    $SUDO mv "$tmpfile" "$daemon_json"
    $SUDO chmod 0644 "$daemon_json"

    $SUDO systemctl restart docker >> "$LOG_FILE" 2>&1
    local attempts=0
    while ! $SUDO docker info &>/dev/null; do
        attempts=$((attempts + 1))
        if [[ $attempts -ge 15 ]]; then
            die "Docker did not restart after IPv6 configuration. Check: journalctl -u docker"
        fi
        sleep 2
    done
    info "Docker IPv6 configured and restarted"
}

prepare_system_user() {
    if [[ "$IS_MACOS" == "true" ]]; then
        return 0
    fi

    if id "$SERVICE_USER" &>/dev/null; then
        info "System user '${SERVICE_USER}' already exists"
    else
        step "  Creating system user '${SERVICE_USER}'..."
        $SUDO useradd --system --no-create-home --shell /usr/sbin/nologin "$SERVICE_USER"
        info "Created system user '${SERVICE_USER}'"
    fi

    if ! groups "$SERVICE_USER" 2>/dev/null | grep -q docker; then
        $SUDO usermod -aG docker "$SERVICE_USER"
        info "Added '${SERVICE_USER}' to docker group"
    fi
}

prepare_firewall() {
    if [[ "$OPT_SKIP_FIREWALL" == "true" ]]; then
        info "Firewall configuration skipped (--skip-firewall)"
        return 0
    fi

    if [[ "$IS_MACOS" == "true" ]]; then
        info "Firewall configuration skipped (macOS)"
        return 0
    fi

    local -a ports=(22/tcp)   # SSH — always open to prevent lockout
    if [[ "$OPT_TLS" == "true" ]]; then
        ports+=(443/tcp)
    else
        ports+=(80/tcp)
    fi
    ports+=(8443/tcp)
    [[ "$OPT_MDNS" == "true" ]] && ports+=(5353/udp)

    step "  Configuring firewall..."
    echo "  Opening ports: ${ports[*]}"

    if command -v ufw &>/dev/null && $SUDO ufw status | grep -q "active"; then
        for port in "${ports[@]}"; do
            $SUDO ufw allow "$port" >> "$LOG_FILE" 2>&1
            info "ufw: opened ${port}"
        done
    elif command -v firewall-cmd &>/dev/null && $SUDO systemctl is-active firewalld &>/dev/null; then
        for port in "${ports[@]}"; do
            $SUDO firewall-cmd --permanent --add-port="$port" >> "$LOG_FILE" 2>&1
            info "firewalld: opened ${port}"
        done
        $SUDO firewall-cmd --reload >> "$LOG_FILE" 2>&1
    elif $SUDO nft list tables 2>/dev/null | grep -q "inet filter"; then
        for port in "${ports[@]}"; do
            local proto="${port##*/}"
            local num="${port%%/*}"
            $SUDO nft add rule inet filter input "$proto" dport "$num" accept >> "$LOG_FILE" 2>&1
            info "nftables: opened ${port}"
        done
    elif command -v iptables &>/dev/null; then
        for port in "${ports[@]}"; do
            local proto="${port##*/}"
            local num="${port%%/*}"
            $SUDO ip6tables -A INPUT -p "$proto" --dport "$num" -j ACCEPT >> "$LOG_FILE" 2>&1
            $SUDO iptables -A INPUT -p "$proto" --dport "$num" -j ACCEPT >> "$LOG_FILE" 2>&1
            info "iptables: opened ${port}"
        done
    else
        warn "No recognized firewall found — skipping. Manually open: ${ports[*]}"
    fi
}

# configure_nftables_docker_forward — fix nftables forward chain for Docker bridges.
#
# Context: Docker containers on bridge networks (backup, grafana, prometheus, consul)
# need the kernel to forward packets between their bridge interface and the default
# route. If nftables has an `inet filter forward` chain with `policy drop` (which
# runs at the same priority as Docker's iptables rules and takes precedence for
# inet/dual-stack tables), ALL Docker bridge traffic is blocked — even though Docker's
# own iptables ACCEPT rules exist.
#
# Note: proxy and traefik use network_mode:host and are unaffected by this.
#
# This function must be called AFTER `deploy_start_remaining_services` so Docker
# bridge interfaces (docker0, br-XXXXX) exist and can be queried.
configure_nftables_docker_forward() {
    if [[ "$OPT_SKIP_FIREWALL" == "true" ]]; then
        return 0
    fi

    if [[ "$IS_MACOS" == "true" ]]; then
        return 0
    fi

    # Only relevant when nftables inet filter table is present
    if ! $SUDO nft list tables 2>/dev/null | grep -q "inet filter"; then
        return 0
    fi

    # Only apply when the forward chain has policy drop
    local forward_policy
    forward_policy=$($SUDO nft list chain inet filter forward 2>/dev/null \
        | grep -oE 'policy (drop|accept)' | awk '{print $2}' || echo "accept")
    if [[ "$forward_policy" != "drop" ]]; then
        return 0
    fi

    info "nftables: inet filter forward policy=drop detected — adding Docker bridge forward rules"

    # Add ct state established,related accept (permits return traffic)
    if ! $SUDO nft list chain inet filter forward 2>/dev/null \
            | grep -q "ct state established"; then
        $SUDO nft add rule inet filter forward ct state established,related accept \
            >> "$LOG_FILE" 2>&1 || true
        info "nftables: added ct state established,related accept"
    fi

    # Always allow docker0 (default bridge)
    local -a bridge_ifaces=("docker0")

    # Discover custom bridge names from running Docker networks
    # Docker sets Options.com.docker.network.bridge.name; if unset the name is
    # derived from the network ID as br-<first 12 chars>.
    if command -v docker &>/dev/null; then
        while IFS= read -r net_id; do
            local bname
            bname=$($SUDO docker network inspect "$net_id" \
                --format '{{index .Options "com.docker.network.bridge.name"}}' \
                2>/dev/null || true)
            if [[ -z "$bname" ]]; then
                # Fallback: br-<first 12 chars of network ID>
                bname="br-${net_id:0:12}"
            fi
            bridge_ifaces+=("$bname")
        done < <($SUDO docker network ls --filter driver=bridge --quiet 2>/dev/null || true)
    fi

    for iface in "${bridge_ifaces[@]}"; do
        [[ -z "$iface" ]] && continue
        # Skip if the interface doesn't exist yet
        if ! $SUDO ip link show "$iface" &>/dev/null 2>&1; then
            continue
        fi
        # Skip if rules already present
        if $SUDO nft list chain inet filter forward 2>/dev/null \
                | grep -q "iifname \"${iface}\""; then
            continue
        fi
        $SUDO nft add rule inet filter forward iifname "$iface" accept \
            >> "$LOG_FILE" 2>&1 || true
        $SUDO nft add rule inet filter forward oifname "$iface" accept \
            >> "$LOG_FILE" 2>&1 || true
        info "nftables: added forward accept rules for ${iface}"
    done

    # Persist to /etc/nftables.conf if it exists (Debian/Ubuntu style)
    if [[ -f /etc/nftables.conf ]]; then
        local tmpfile
        tmpfile=$(mktemp /tmp/nft-llap-XXXXXX.conf)
        if $SUDO nft list ruleset > "$tmpfile" 2>/dev/null && [[ -s "$tmpfile" ]]; then
            $SUDO mv "$tmpfile" /etc/nftables.conf
            info "nftables: persisted rules to /etc/nftables.conf"
        else
            rm -f "$tmpfile"
            warn "nftables: could not persist rules — manually run: nft list ruleset > /etc/nftables.conf"
        fi
    fi
}

prepare_security_updates() {
    if [[ "$OPT_SKIP_SECURITY_UPDATES" == "true" ]]; then
        info "Automatic security updates skipped (--skip-security-updates)"
        return 0
    fi

    if [[ "$IS_MACOS" == "true" ]]; then
        return 0
    fi

    step "  Configuring automatic security updates..."
    case "$PKG_MANAGER" in
        apt)
            $SUDO env DEBIAN_FRONTEND=noninteractive apt-get install -y -qq unattended-upgrades >> "$LOG_FILE" 2>&1
            $SUDO env DEBIAN_FRONTEND=noninteractive dpkg-reconfigure -plow unattended-upgrades >> "$LOG_FILE" 2>&1 || true
            info "unattended-upgrades configured"
            ;;
        dnf)
            $SUDO dnf install -y -q dnf-automatic >> "$LOG_FILE" 2>&1
            $SUDO sed -i 's/^apply_updates = no/apply_updates = yes/' /etc/dnf/automatic.conf 2>/dev/null || true
            $SUDO systemctl enable --now dnf-automatic.timer >> "$LOG_FILE" 2>&1
            info "dnf-automatic configured"
            ;;
        yum)
            $SUDO yum install -y -q yum-cron >> "$LOG_FILE" 2>&1
            $SUDO systemctl enable --now yum-cron >> "$LOG_FILE" 2>&1
            info "yum-cron configured"
            ;;
        *)
            warn "Auto security updates not configured for ${PKG_MANAGER}"
            ;;
    esac
}

run_prepare() {
    step "[3/5] Preparing system..."
    local step_num=0
    local total_steps=7

    step_num=$((step_num + 1))
    echo "  [${step_num}/${total_steps}] System package upgrade"
    prepare_system_upgrade

    step_num=$((step_num + 1))
    echo "  [${step_num}/${total_steps}] Prerequisites"
    prepare_prerequisites

    step_num=$((step_num + 1))
    echo "  [${step_num}/${total_steps}] Docker"
    prepare_docker

    step_num=$((step_num + 1))
    echo "  [${step_num}/${total_steps}] Docker IPv6"
    prepare_docker_ipv6

    step_num=$((step_num + 1))
    echo "  [${step_num}/${total_steps}] System user"
    prepare_system_user

    step_num=$((step_num + 1))
    echo "  [${step_num}/${total_steps}] Firewall"
    prepare_firewall

    step_num=$((step_num + 1))
    echo "  [${step_num}/${total_steps}] Security updates"
    prepare_security_updates

    info "System preparation complete"
}

# ── Phase 4: Configure (settings collection) ────────────────────────────────

configure_install_mode() {
    if [[ -z "${EXISTING_INSTALL:-}" ]]; then
        if [[ -z "$COMMAND" ]]; then
            COMMAND="install"
        fi
        return 0
    fi

    if [[ -n "$COMMAND" ]]; then
        return 0
    fi

    if [[ "$OPT_NON_INTERACTIVE" == "true" ]]; then
        COMMAND="upgrade"
        return 0
    fi

    local choice
    if [[ -n "$DIALOG_CMD" ]] && [[ -t 0 ]]; then
        choice=$("$DIALOG_CMD" --title "Existing Installation" --menu \
            "An existing installation was found. What would you like to do?" \
            12 60 3 \
            "upgrade" "Upgrade to new version" \
            "reconfigure" "Change settings" \
            "reinstall" "Full reinstall (warning: may lose data)" \
            3>&1 1>&2 2>&3) || die "Cancelled."
    else
        echo ""
        echo "Existing installation detected. Choose:"
        echo "  1) Upgrade to new version"
        echo "  2) Reconfigure settings"
        echo "  3) Full reinstall"
        local answer
        read -r -p "Choice [1]: " answer
        case "${answer:-1}" in
            1) choice="upgrade" ;;
            2) choice="reconfigure" ;;
            3) choice="reinstall" ;;
            *) choice="upgrade" ;;
        esac
    fi

    if [[ "$choice" == "reinstall" ]]; then
        if ! ask_yesno "Full Reinstall" "This will reinstall from scratch. Existing data in Docker volumes is preserved but config will be regenerated. Continue?" "no"; then
            die "Aborted."
        fi
        COMMAND="install"
    else
        COMMAND="$choice"
    fi
}

configure_version() {
    if [[ -n "$OPT_VERSION" ]]; then
        info "Version: ${OPT_VERSION} (from CLI/env)"
        return 0
    fi

    local latest=""

    if [[ "$OPT_DEBUG" == "true" ]]; then
        # Debug images are not published to the public releases repo.
        # Fall back to GHCR tag list which requires auth (may return 401 without a PAT).
        local scope="repository:llm-api-proxy/server-debug:pull"
        local tags_json
        if tags_json=$(ghcr_api_request "https://ghcr.io/v2/llm-api-proxy/server-debug/tags/list" "$scope"); then
            latest=$(echo "$tags_json" | jq -r '.tags[]' 2>/dev/null \
                | grep -E '^[0-9]+\.[0-9]+\.[0-9]+-debug$' | sort -V | tail -1)
            latest="${latest%-debug}"
        fi
    else
        # Query the public GitHub Releases API — no auth required.
        local releases_url="https://api.github.com/repos/LLM-API-Proxy/llap/releases?per_page=10"
        local releases_json
        if releases_json=$(curl -fsSL --max-time 10 \
                -H "Accept: application/vnd.github+json" \
                "$releases_url" 2>/dev/null); then
            latest=$(echo "$releases_json" \
                | jq -r '[.[] | select(.prerelease==false and .draft==false) | .tag_name] | first' \
                2>/dev/null | sed 's/^v//')
        fi
    fi

    if [[ -n "$latest" ]] && [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
        OPT_VERSION=$(ask_input "Version" "Enter version to install" "$latest")
    elif [[ -n "$latest" ]]; then
        OPT_VERSION="$latest"
    else
        if [[ "$OPT_NON_INTERACTIVE" == "true" ]]; then
            OPT_VERSION="edge"
        else
            OPT_VERSION=$(ask_input "Version" "Could not query releases. Enter version" "edge")
        fi
    fi

    info "Version: ${OPT_VERSION}"
}

configure_features() {
    if [[ "$OPT_NON_INTERACTIVE" == "true" ]]; then
        return 0
    fi

    local mdns_state="on"
    [[ "$IS_MACOS" == "true" ]] && mdns_state="off"

    local selected
    selected=$(ask_checklist "Components" "Select components to install:" \
        "waf" "WAF (ModSecurity OWASP CRS)" "$([ "$OPT_WAF" = "true" ] && echo on || echo off)" \
        "tls" "TLS (automated HTTPS via Traefik)" "$([ "$OPT_TLS" = "true" ] && echo on || echo off)" \
        "backup" "Backup (Restic to S3)" "$([ "$OPT_BACKUP" = "true" ] && echo on || echo off)" \
        "monitoring" "Monitoring (Prometheus + Grafana)" "$([ "$OPT_MONITORING" = "true" ] && echo on || echo off)" \
        "mdns" "mDNS service discovery" "$mdns_state") || return 0

    OPT_WAF="false"; OPT_TLS="false"; OPT_BACKUP="false"
    OPT_MONITORING="false"; OPT_MDNS="false"
    local item
    for item in $selected; do
        item=$(echo "$item" | tr -d '"')
        case "$item" in
            waf) OPT_WAF="true" ;;
            tls) OPT_TLS="true" ;;
            backup) OPT_BACKUP="true" ;;
            monitoring) OPT_MONITORING="true" ;;
            mdns) OPT_MDNS="true" ;;
        esac
    done

    [[ "$IS_MACOS" == "true" ]] && OPT_MDNS="false"
}

configure_core() {
    step "  Core settings..."

    if [[ -z "$OPT_POSTGRES_PASSWORD" ]]; then
        OPT_POSTGRES_PASSWORD=$(resolve_setting "OPT_POSTGRES_PASSWORD" "POSTGRES_PASSWORD" \
            "PostgreSQL password" "$(openssl rand -base64 24 2>/dev/null || head -c 24 /dev/urandom | base64)")
    fi

    if [[ -z "$OPT_KEK_HEX" ]]; then
        local existing_kek=""
        if $SUDO test -f "${INSTALL_DIR}/docker/.env" 2>/dev/null; then
            existing_kek=$($SUDO grep "^PROXY_KEK_VALUE=" "${INSTALL_DIR}/docker/.env" 2>/dev/null | cut -d= -f2- || true)
        fi
        if [[ -n "$existing_kek" ]]; then
            OPT_KEK_HEX="$existing_kek"
        else
            OPT_KEK_HEX=$(openssl rand -hex 32 2>/dev/null || head -c 32 /dev/urandom | xxd -p | tr -d '\n')
        fi
    fi

    if [[ "${COMMAND:-}" == "reconfigure" ]] && $SUDO test -f "${INSTALL_DIR}/docker/.env" 2>/dev/null; then
        local old_kek
        old_kek=$($SUDO grep "^PROXY_KEK_VALUE=" "${INSTALL_DIR}/docker/.env" 2>/dev/null | cut -d= -f2- || true)
        if [[ -n "$old_kek" ]] && [[ "$old_kek" != "$OPT_KEK_HEX" ]]; then
            warn "KEK is changing! All encrypted provider credentials will become unreadable."
            if [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
                if ! ask_yesno "KEK Change" "Changing the KEK invalidates all encrypted credentials. Continue?" "no"; then
                    OPT_KEK_HEX="$old_kek"
                fi
            fi
        fi
    fi

    # ── Proxy key pepper ───────────────────────────────────────────────────────
    local existing_pepper=""
    if $SUDO test -f "${INSTALL_DIR}/docker/.env" 2>/dev/null; then
        existing_pepper=$($SUDO grep "^PROXY_PROXY_KEY_PEPPER=" "${INSTALL_DIR}/docker/.env" \
            2>/dev/null | cut -d= -f2- | tr -d '"' || true)
    fi

    if [[ -z "$OPT_PROXY_KEY_PEPPER" ]]; then
        if [[ -n "$existing_pepper" ]]; then
            OPT_PROXY_KEY_PEPPER="$existing_pepper"
            log "Preserving existing PROXY_PROXY_KEY_PEPPER"
        else
            OPT_PROXY_KEY_PEPPER=$(openssl rand -hex 32 2>/dev/null || head -c 32 /dev/urandom | xxd -p | tr -d '\n')
            log "Generated new PROXY_PROXY_KEY_PEPPER"
            warn "IMPORTANT: Save your PROXY_PROXY_KEY_PEPPER value securely."
            warn "This value must be IDENTICAL on the destination server when migrating credentials."
            warn "Losing this value will break proxy key validation after a migration."
        fi
    fi

    # Warn if pepper is changing on reconfigure
    if [[ "${COMMAND:-}" == "reconfigure" ]] && \
       [[ -n "$existing_pepper" ]] && \
       [[ "$existing_pepper" != "$OPT_PROXY_KEY_PEPPER" ]]; then
        warn "WARNING: PROXY_PROXY_KEY_PEPPER is changing!"
        warn "All existing proxy key hashes will become INVALID."
        warn "Users will need to regenerate their proxy keys after reconfiguration."
    fi

    # ── JWT secret ─────────────────────────────────────────────────────────────
    # Preserve existing JWT secret on upgrades to avoid invalidating all sessions.
    if [[ -z "$OPT_JWT_SECRET" ]]; then
        local existing_jwt=""
        if $SUDO test -f "${INSTALL_DIR}/docker/.env" 2>/dev/null; then
            existing_jwt=$($SUDO grep "^PROXY_JWT_SECRET=" "${INSTALL_DIR}/docker/.env" \
                2>/dev/null | cut -d= -f2- || true)
        fi
        if [[ -n "$existing_jwt" ]]; then
            OPT_JWT_SECRET="$existing_jwt"
            log "Preserving existing PROXY_JWT_SECRET"
        else
            OPT_JWT_SECRET=$(openssl rand -hex 32 2>/dev/null || head -c 32 /dev/urandom | xxd -p | tr -d '\n')
        fi
    fi

    if [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
        OPT_LISTEN_PORT=$(ask_input "Port" "Proxy HTTP service port" "${OPT_LISTEN_PORT}")
        OPT_FORWARD_PROXY_PORT=$(ask_input "Port" "Forward proxy CONNECT port" "${OPT_FORWARD_PROXY_PORT}")
    fi
}

configure_tls() {
    [[ "$OPT_TLS" != "true" ]] && return 0

    # In non-interactive mode, TLS requires --domain= to be set.
    # Without it, disable TLS rather than dying — the user can reconfigure later.
    if [[ "$OPT_NON_INTERACTIVE" == "true" ]] && [[ -z "${OPT_DOMAIN:-}" ]]; then
        if [[ ! -f "${INSTALL_DIR:-}/docker/.env" ]] || ! $SUDO grep -q "^PROXY_TLS__DOMAIN=" "${INSTALL_DIR}/docker/.env" 2>/dev/null; then
            warn "TLS disabled — no --domain= provided. Reconfigure with: install.sh reconfigure --domain=your.host"
            OPT_TLS="false"
            return 0
        fi
    fi

    step "  TLS settings..."

    OPT_DOMAIN=$(resolve_setting "OPT_DOMAIN" "PROXY_TLS__DOMAIN" "Enter your public hostname (e.g., proxy.example.com)" "")
    OPT_ACME_EMAIL=$(resolve_setting "OPT_ACME_EMAIL" "PROXY_TLS__ACME_EMAIL" "Email for Let's Encrypt notifications" "")

    if [[ -z "$OPT_CF_DNS_API_TOKEN" ]] && [[ -z "$OPT_CF_API_KEY" ]]; then
        local existing_token existing_key
        existing_token=$($SUDO grep "^CF_DNS_API_TOKEN=" "${INSTALL_DIR}/docker/.env" 2>/dev/null | cut -d= -f2- || true)
        existing_key=$($SUDO grep "^CF_API_KEY=" "${INSTALL_DIR}/docker/.env" 2>/dev/null | cut -d= -f2- || true)

        if [[ -n "$existing_token" ]]; then
            OPT_CF_DNS_API_TOKEN="$existing_token"
        elif [[ -n "$existing_key" ]]; then
            OPT_CF_API_KEY="$existing_key"
            OPT_CF_API_EMAIL=$($SUDO grep "^CF_API_EMAIL=" "${INSTALL_DIR}/docker/.env" 2>/dev/null | cut -d= -f2- || true)
        elif [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
            if ask_yesno "Cloudflare Auth" "Use scoped API token (recommended)? No=use global API key" "yes"; then
                OPT_CF_DNS_API_TOKEN=$(ask_password "Cloudflare" "Enter Cloudflare scoped API token")
            else
                warn "Global API key has broad permissions. Consider a scoped token."
                OPT_CF_API_EMAIL=$(ask_input "Cloudflare" "Cloudflare account email" "")
                OPT_CF_API_KEY=$(ask_password "Cloudflare" "Enter Cloudflare global API key")
            fi
        fi
    fi
}

configure_backup() {
    [[ "$OPT_BACKUP" != "true" ]] && return 0

    # In non-interactive mode, backup requires S3 credentials. Disable if missing.
    if [[ "$OPT_NON_INTERACTIVE" == "true" ]] && [[ -z "${OPT_RESTIC_REPOSITORY:-}" ]] && [[ -z "${OPT_AWS_ACCESS_KEY_ID:-}" ]]; then
        if [[ ! -f "${INSTALL_DIR:-}/docker/.env" ]] || ! $SUDO grep -q "^RESTIC_REPOSITORY=" "${INSTALL_DIR}/docker/.env" 2>/dev/null; then
            warn "Backup disabled — no S3 credentials provided. Reconfigure with: install.sh reconfigure"
            OPT_BACKUP="false"
            return 0
        fi
    fi

    step "  Backup settings..."

    OPT_RESTIC_REPOSITORY=$(resolve_setting "OPT_RESTIC_REPOSITORY" "RESTIC_REPOSITORY" \
        "Restic repository URL (e.g., s3:s3.amazonaws.com/mybucket/llm-proxy)" "")

    if [[ -z "$OPT_RESTIC_PASSWORD" ]]; then
        OPT_RESTIC_PASSWORD=$(resolve_setting "OPT_RESTIC_PASSWORD" "RESTIC_PASSWORD" \
            "Restic encryption password" "$(openssl rand -base64 24 2>/dev/null || head -c 24 /dev/urandom | base64)")
    fi

    OPT_AWS_ACCESS_KEY_ID=$(resolve_setting "OPT_AWS_ACCESS_KEY_ID" "AWS_ACCESS_KEY_ID" "AWS Access Key ID" "")
    OPT_AWS_SECRET_ACCESS_KEY=$(resolve_setting "OPT_AWS_SECRET_ACCESS_KEY" "AWS_SECRET_ACCESS_KEY" "AWS Secret Access Key" "")

    if [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
        OPT_BACKUP_SCHEDULE=$(ask_input "Backup" "Backup schedule (cron expression)" "${OPT_BACKUP_SCHEDULE}")
    fi
}

configure_monitoring() {
    [[ "$OPT_MONITORING" != "true" ]] && return 0
    step "  Monitoring settings..."

    if [[ -z "$OPT_GRAFANA_PASSWORD" ]]; then
        OPT_GRAFANA_PASSWORD=$(resolve_setting "OPT_GRAFANA_PASSWORD" "GRAFANA_PASSWORD" \
            "Grafana admin password" "$(openssl rand -base64 16 2>/dev/null || head -c 16 /dev/urandom | base64)")
    fi

    if [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
        OPT_GRAFANA_PORT=$(ask_input "Monitoring" "Grafana port" "${OPT_GRAFANA_PORT}")
        OPT_PROMETHEUS_PORT=$(ask_input "Monitoring" "Prometheus port" "${OPT_PROMETHEUS_PORT}")
    fi
}

configure_review() {
    if [[ "$OPT_NON_INTERACTIVE" == "true" ]]; then
        return 0
    fi

    local features=""
    [[ "$OPT_WAF" == "true" ]] && features+="WAF "
    [[ "$OPT_TLS" == "true" ]] && features+="TLS "
    [[ "$OPT_BACKUP" == "true" ]] && features+="Backup "
    [[ "$OPT_MONITORING" == "true" ]] && features+="Monitor "
    [[ "$OPT_MDNS" == "true" ]] && features+="mDNS "

    local tls_line=""
    [[ "$OPT_TLS" == "true" ]] && tls_line="Domain: ${OPT_DOMAIN}"

    draw_box "Installation Summary" \
        "Version:    ${OPT_VERSION}" \
        "Directory:  ${INSTALL_DIR}" \
        "Components: ${features}" \
        "${tls_line}" \
        "DB Pass:    $(mask_secret "$OPT_POSTGRES_PASSWORD")" \
        "KEK:        $(mask_secret "$OPT_KEK_HEX")" \
        "" \
        "Proceed with installation?"

    if ! ask_yesno "Confirm" "Proceed with installation?" "yes"; then
        configure_features
        configure_core
        [[ "$OPT_TLS" == "true" ]] && configure_tls
        [[ "$OPT_BACKUP" == "true" ]] && configure_backup
        [[ "$OPT_MONITORING" == "true" ]] && configure_monitoring
        configure_review
    fi
}

# ── Debug profile configuration ───────────────────────────────────────────────

# Displays the full debug profile security warning box.
_show_full_profile_warning() {
    draw_box "SECURITY WARNING — Full Debug Profile" \
        "Full profile enables SYS_PTRACE capability and" \
        "disables the read-only filesystem on the proxy" \
        "container. This significantly reduces isolation." \
        "" \
        "Only use Full profile for active debugging sessions." \
        "Do NOT run Full profile in production or on" \
        "internet-exposed hosts."
}

# Present debug profile selection dialog.
# Called from run_configure() when OPT_DEBUG=true.
# Skips dialog if profile already set via CLI, env var, or .env restore.
configure_debug_profile() {
    [[ "$OPT_DEBUG" == "true" ]] || return 0

    if [[ "$OPT_DEBUG_PROFILE_SET" == "false" && "$OPT_NON_INTERACTIVE" == "false" ]]; then
        local minimal_state="off" moderate_state="on" full_state="off"
        case "$OPT_DEBUG_PROFILE" in
            minimal)  minimal_state="on";  moderate_state="off" ;;
            full)     full_state="on";     moderate_state="off" ;;
        esac

        while true; do
            local selected
            selected=$(ask_radiolist "Debug Profile" "Select debug profile:" \
                minimal "Minimal — image swap only" "$minimal_state" \
                moderate "Moderate — +RUST_LOG=debug, RUST_BACKTRACE=1" "$moderate_state" \
                full "Full — +SYS_PTRACE (reduces isolation)" "$full_state")
            OPT_DEBUG_PROFILE="$selected"

            if [[ "$OPT_DEBUG_PROFILE" == "full" ]]; then
                _show_full_profile_warning
                if ask_yesno "Full Profile" "Continue with full debug profile?" "no"; then
                    break
                fi
                minimal_state="off"; moderate_state="on"; full_state="off"
                OPT_DEBUG_PROFILE="moderate"
                continue
            fi
            break
        done
        OPT_DEBUG_PROFILE_SET="true"
        return 0
    fi

    # Non-interactive or pre-set: always show the warning for full profile
    if [[ "$OPT_DEBUG_PROFILE" == "full" ]]; then
        _show_full_profile_warning
    fi
}

run_configure() {
    step "[4/5] Collecting configuration..."
    configure_install_mode
    configure_version
    configure_features
    configure_debug_profile
    configure_core
    configure_tls
    configure_backup
    configure_monitoring
    configure_review
    info "Configuration complete"
}

# ── Phase 5: Deploy ──────────────────────────────────────────────────────────

deploy_create_dirs() {
    step "  Creating install directory..."
    $SUDO mkdir -p "${INSTALL_DIR}/docker/modsecurity"
    $SUDO mkdir -p "${INSTALL_DIR}/docker/prometheus"
    $SUDO mkdir -p "${INSTALL_DIR}/docker/grafana/provisioning/dashboards"
    $SUDO mkdir -p "${INSTALL_DIR}/docker/grafana/provisioning/datasources"
    $SUDO mkdir -p "${METADATA_DIR}"

    if [[ "$IS_MACOS" != "true" ]]; then
        $SUDO chown -R "${SERVICE_USER}:${SERVICE_USER}" "${INSTALL_DIR}"
        $SUDO chmod 0750 "${INSTALL_DIR}"
        $SUDO chown root:root "${METADATA_DIR}"
        $SUDO chmod 0755 "${METADATA_DIR}"
    fi
    info "Install directory created: ${INSTALL_DIR}"
}

deploy_extract_files() {
    step "  Extracting embedded files..."
    extract_file EMBED_docker_compose_yml "${INSTALL_DIR}/docker/docker-compose.yml"
    extract_file EMBED_docker_compose_hardened_yml "${INSTALL_DIR}/docker/docker-compose.hardened.yml"

    [[ "$OPT_WAF" == "true" ]] && {
        extract_file EMBED_docker_compose_waf_yml "${INSTALL_DIR}/docker/docker-compose.waf.yml"
        extract_file EMBED_modsecurity_exclusion_rules "${INSTALL_DIR}/docker/modsecurity/REQUEST-900-EXCLUSION-RULES-BEFORE-CRS.conf"
    }
    [[ "$OPT_TLS" == "true" ]] && \
        extract_file EMBED_docker_compose_tls_yml "${INSTALL_DIR}/docker/docker-compose.tls.yml"
    [[ "$OPT_MONITORING" == "true" ]] && {
        extract_file EMBED_docker_compose_monitoring_yml "${INSTALL_DIR}/docker/docker-compose.monitoring.yml"
        # Monitoring config files are bind-mounted into containers that run as
        # non-root UIDs — they need world-readable (0644) permissions.
        extract_file EMBED_prometheus_prometheus_yml "${INSTALL_DIR}/docker/prometheus/prometheus.yml" 0644
        extract_file EMBED_grafana_dashboard_yml "${INSTALL_DIR}/docker/grafana/provisioning/dashboards/dashboard.yml" 0644
        extract_file EMBED_grafana_proxy_json "${INSTALL_DIR}/docker/grafana/provisioning/dashboards/proxy.json" 0644
        extract_file EMBED_grafana_backup_health_json "${INSTALL_DIR}/docker/grafana/provisioning/dashboards/backup-health.json" 0644
        extract_file EMBED_grafana_datasources_yml "${INSTALL_DIR}/docker/grafana/provisioning/datasources/prometheus.yml" 0644
    }
    [[ "$OPT_BACKUP" == "true" ]] && \
        extract_file EMBED_docker_compose_backup_yml "${INSTALL_DIR}/docker/docker-compose.backup.yml"
    if [[ "$IS_MACOS" == "true" ]] && [[ "$MACOS_HOST_NETWORKING" != "true" ]]; then
        # Bridge networking mode: extract the no-mdns overlay for Docker Compose.
        # When host networking is active, PROXY_MDNS__ENABLED=false in .env is sufficient.
        extract_file EMBED_docker_compose_no_mdns_yml "${INSTALL_DIR}/docker/docker-compose.no-mdns.yml"
    fi
    [[ "$OPT_MDNS" != "true" ]] && [[ "$IS_MACOS" != "true" ]] && \
        extract_file EMBED_docker_compose_no_mdns_yml "${INSTALL_DIR}/docker/docker-compose.no-mdns.yml"

    extract_file EMBED_config_example_toml "${INSTALL_DIR}/config.example.toml"

    if [[ "$OPT_DEBUG" == "true" ]]; then
        deploy_write_debug_overlay
    else
        # Clean up debug overlay if downgrading from debug to production
        $SUDO rm -f "${INSTALL_DIR}/docker/docker-compose.debug.yml"
    fi

    info "Files extracted"
}

# Generate docker-compose.debug.yml overlay dynamically based on OPT_DEBUG_PROFILE.
# Called from deploy_extract_files() when OPT_DEBUG=true.
# The overlay is NOT in files.manifest — it is dynamically generated.
# SECURITY NOTE: Backup service MUST only use BACKUP_LOG_LEVEL=debug.
#   NEVER use set -x, BACKUP_DEBUG=true, or any command-tracing mechanism
#   in the backup environment. The backup script handles Consul ACL tokens,
#   PostgreSQL passwords, and S3 credentials.
deploy_write_debug_overlay() {
    local overlay_file="${INSTALL_DIR}/docker/docker-compose.debug.yml"
    local version_tag="${OPT_VERSION:-edge}-debug"

    step "  Writing docker-compose.debug.yml (profile: ${OPT_DEBUG_PROFILE})..."

    {
        echo "# docker-compose.debug.yml — generated by install.sh"
        echo "# Profile: ${OPT_DEBUG_PROFILE} — INTERNAL USE ONLY"
        echo "# DO NOT EDIT — regenerated on each install/upgrade"
        echo "services:"
        echo "  proxy:"
        echo "    image: ghcr.io/llm-api-proxy/server-debug:${version_tag}"

        if [[ "$OPT_DEBUG_PROFILE" == "moderate" || "$OPT_DEBUG_PROFILE" == "full" ]]; then
            echo "    environment:"
            echo "      RUST_LOG: debug"
            echo "      RUST_BACKTRACE: '1'"
        fi

        if [[ "$OPT_DEBUG_PROFILE" == "full" ]]; then
            echo "    read_only: false"
            echo "    cap_add:"
            echo "      - SYS_PTRACE"
        fi

        if [[ "$OPT_BACKUP" == "true" ]]; then
            echo "  backup:"
            echo "    image: ghcr.io/llm-api-proxy/backup-debug:${version_tag}"
            if [[ "$OPT_DEBUG_PROFILE" == "moderate" || "$OPT_DEBUG_PROFILE" == "full" ]]; then
                echo "    environment:"
                echo "      BACKUP_LOG_LEVEL: debug"
            fi
        fi
    } | $SUDO tee "$overlay_file" > /dev/null

    $SUDO chmod 0640 "$overlay_file"
    info "docker-compose.debug.yml written"
}

deploy_write_env() {
    step "  Writing .env configuration..."
    local env_file="${INSTALL_DIR}/docker/.env"

    # SAFETY: Always backup the existing .env before overwriting.
    # This is the last line of defence against secret loss (KEK, pepper,
    # JWT secret, restic password) if the install/upgrade flow
    # incorrectly falls through to a fresh write.
    if $SUDO test -f "$env_file" 2>/dev/null; then
        local safety_backup
        safety_backup="${env_file}.backup.$(date +%Y%m%d-%H%M%S)"
        $SUDO cp "$env_file" "$safety_backup"
        warn "Existing .env backed up to ${safety_backup}"
    fi

    local tmpfile
    tmpfile=$(mktemp)

    local gen_date
    gen_date=$(date -u +%Y-%m-%dT%H:%M:%SZ)
    {
        printf '# %s\n' "══════════════════════════════════════════════════════════════"
        printf '# LLM API Proxy — Environment Configuration\n'
        printf '# Generated by install.sh v%s on %s\n' "$INSTALLER_VERSION" "$gen_date"
        printf '# %s\n' "══════════════════════════════════════════════════════════════"
        printf '\n# ── Version ──────────────────────────────────────────────────\n'
        printf 'PROXY_VERSION=%s\n' "$OPT_VERSION"
        printf '\n# ── Core ─────────────────────────────────────────────────────\n'
        printf 'POSTGRES_DB=llm_proxy\n'
        printf 'POSTGRES_USER=proxy\n'
        printf 'POSTGRES_PASSWORD=%s\n' "$OPT_POSTGRES_PASSWORD"
        printf 'PROXY_KEK_VALUE=%s\n' "$OPT_KEK_HEX"
        printf 'PROXY_PROXY_KEY_PEPPER=%s\n' "$OPT_PROXY_KEY_PEPPER"
        printf 'PROXY_JWT_SECRET=%s\n' "$OPT_JWT_SECRET"
        printf 'RUST_LOG=info\n'
        printf 'LOG_FORMAT=json\n'
        printf 'PROXY_LISTEN_ADDR=::\n'
        printf 'PROXY_LISTEN_PORT=%s\n' "$OPT_LISTEN_PORT"
        printf 'PROXY_FORWARD_PROXY_PORT=%s\n' "$OPT_FORWARD_PROXY_PORT"
    } > "$tmpfile"

    if [[ "$OPT_TLS" == "true" ]]; then
        {
            printf '\n# ── TLS ──────────────────────────────────────────────────────\n'
            printf 'PROXY_TLS__ENABLED=true\n'
            printf 'PROXY_TLS__DOMAIN=%s\n' "$OPT_DOMAIN"
            printf 'PROXY_TLS__ACME_EMAIL=%s\n' "$OPT_ACME_EMAIL"
        } >> "$tmpfile"
        if [[ -n "${OPT_CF_DNS_API_TOKEN:-}" ]]; then
            printf 'CF_DNS_API_TOKEN=%s\n' "$OPT_CF_DNS_API_TOKEN" >> "$tmpfile"
        elif [[ -n "${OPT_CF_API_KEY:-}" ]]; then
            printf 'CF_API_EMAIL=%s\n' "$OPT_CF_API_EMAIL" >> "$tmpfile"
            printf 'CF_API_KEY=%s\n' "$OPT_CF_API_KEY" >> "$tmpfile"
        fi
    fi

    if [[ "$OPT_BACKUP" == "true" ]]; then
        {
            printf '\n# ── Backup ───────────────────────────────────────────────────\n'
            printf 'RESTIC_REPOSITORY=%s\n' "$OPT_RESTIC_REPOSITORY"
            printf 'RESTIC_PASSWORD=%s\n' "$OPT_RESTIC_PASSWORD"
            printf 'AWS_ACCESS_KEY_ID=%s\n' "$OPT_AWS_ACCESS_KEY_ID"
            printf 'AWS_SECRET_ACCESS_KEY=%s\n' "$OPT_AWS_SECRET_ACCESS_KEY"
            printf 'BACKUP_SCHEDULE=%s\n' "$OPT_BACKUP_SCHEDULE"
        } >> "$tmpfile"
    fi

    if [[ "$OPT_MONITORING" == "true" ]]; then
        {
            printf '\n# ── Monitoring ───────────────────────────────────────────────\n'
            printf 'GRAFANA_PASSWORD=%s\n' "$OPT_GRAFANA_PASSWORD"
            printf 'GRAFANA_PORT=%s\n' "$OPT_GRAFANA_PORT"
            printf 'PROMETHEUS_PORT=%s\n' "$OPT_PROMETHEUS_PORT"
        } >> "$tmpfile"
    fi

    # macOS: mDNS is always disabled — multicast does not cross the Docker Desktop
    # VM boundary regardless of host networking mode. Write this unconditionally
    # so the proxy service never attempts mDNS advertisement on macOS.
    if [[ "$IS_MACOS" == "true" ]]; then
        {
            printf '\n# ── macOS: mDNS disabled (Docker Desktop VM boundary) ────────\n'
            printf 'PROXY_MDNS__ENABLED=false\n'
        } >> "$tmpfile"
    fi

    {
        printf '\n# ── Debug containers ─────────────────────────────────────────\n'
        printf 'PROXY_DEBUG=%s\n' "$OPT_DEBUG"
        printf 'PROXY_DEBUG_PROFILE=%s\n' "$OPT_DEBUG_PROFILE"
    } >> "$tmpfile"

    $SUDO chmod 0640 "$tmpfile"
    if [[ "$IS_MACOS" != "true" ]]; then
        $SUDO chown "root:${SERVICE_USER}" "$tmpfile" 2>/dev/null || true
    fi

    $SUDO mv "$tmpfile" "$env_file"
    info ".env written (atomic)"
    log "ENV: $($SUDO grep -c '=' "$env_file") variables set"
}

deploy_upgrade_env() {
    local env_file="${INSTALL_DIR}/docker/.env"
    if [[ ! -f "$env_file" ]]; then
        deploy_write_env
        return 0
    fi

    local backup
    backup="${env_file}.backup.$(date +%Y%m%d-%H%M%S)"
    $SUDO cp "$env_file" "$backup"
    info "Backed up .env to ${backup}"

    $SUDO sed -i "s/^PROXY_VERSION=.*/PROXY_VERSION=${OPT_VERSION}/" "$env_file"

    local ref_file
    ref_file=$(mktemp); CLEANUP_FILES+=("$ref_file")
    local old_env_file="${env_file}"
    local old_install_dir="${INSTALL_DIR}"
    INSTALL_DIR=$(mktemp -d); CLEANUP_FILES+=("$INSTALL_DIR")
    mkdir -p "${INSTALL_DIR}/docker"
    deploy_write_env
    mv "${INSTALL_DIR}/docker/.env" "$ref_file"
    rm -rf "$INSTALL_DIR"
    INSTALL_DIR="$old_install_dir"

    local new_keys
    new_keys=$(comm -23 <(sed -n 's/^\([A-Z_]*\)=.*/\1/p' "$ref_file" | sort) \
                        <(sed -n 's/^\([A-Z_]*\)=.*/\1/p' "$old_env_file" | sort) || true)

    if [[ -n "$new_keys" ]]; then
        echo "" | $SUDO tee -a "$old_env_file" > /dev/null
        echo "# Added by upgrade to v${OPT_VERSION} on $(date -u +%Y-%m-%dT%H:%M:%SZ)" | $SUDO tee -a "$old_env_file" > /dev/null
        while IFS= read -r key; do
            local value
            value=$(grep "^${key}" "$ref_file" | head -1 || true)
            if [[ -n "$value" ]]; then
                echo "$value" | $SUDO tee -a "$old_env_file" > /dev/null
                info "Added new variable: ${key%%=*}"
            fi
        done <<< "$new_keys"
    fi

    deploy_upgrade_debug_state
}

# Load debug state persisted from a previous install/upgrade.
# Called after detect_os() (which resolves INSTALL_DIR) and before the warning gate.
# Respects CLI flags and env vars — does NOT override them.
load_debug_state_from_env() {
    local env_file="${INSTALL_DIR}/docker/.env"
    [[ -f "$env_file" ]] || return 0

    # Read persisted values (|| true prevents set -e exit when key is absent)
    local persisted_debug persisted_profile
    persisted_debug=$(grep -E '^PROXY_DEBUG=' "$env_file" 2>/dev/null | tail -1 | cut -d= -f2- || true)
    persisted_profile=$(grep -E '^PROXY_DEBUG_PROFILE=' "$env_file" 2>/dev/null | tail -1 | cut -d= -f2- || true)

    # Apply persisted debug flag only if not overridden by CLI or env var
    if [[ "$OPT_DEBUG" == "false" && "$OPT_NO_DEBUG" == "false" && -n "$persisted_debug" ]]; then
        OPT_DEBUG="$persisted_debug"
    fi

    # Apply persisted profile only if not already set explicitly AND debug is on.
    # When PROXY_DEBUG=false the profile is irrelevant — loading it would trip the
    # deferred validation below ("--debug-profile requires --debug") on upgrade.
    if [[ "$OPT_DEBUG_PROFILE_SET" == "false" && "$OPT_DEBUG" == "true" && -n "$persisted_profile" ]]; then
        # Validate profile value (handle malformed .env)
        case "$persisted_profile" in
            minimal|moderate|full)
                OPT_DEBUG_PROFILE="$persisted_profile"
                OPT_DEBUG_PROFILE_SET="true"  # treat as explicit to skip the dialog
                ;;
            *)
                warn "Invalid PROXY_DEBUG_PROFILE in .env: '${persisted_profile}' — defaulting to moderate"
                OPT_DEBUG_PROFILE="moderate"
                ;;
        esac
    fi

    # Deferred validation: --debug-profile= without effective debug mode
    if [[ "$OPT_DEBUG_PROFILE_SET" == "true" && "$OPT_DEBUG" == "false" && "$OPT_NO_DEBUG" == "false" ]]; then
        die "--debug-profile requires --debug (or PROXY_DEBUG=true in .env)"
    fi
}

# Display INTERNAL USE ONLY warning and confirmation when debug mode is active.
# Called after load_debug_state_from_env() and before run_preflight().
# Skips confirmation gate in non-interactive mode, but always shows the warning.
warn_debug_mode() {
    [[ "$OPT_DEBUG" == "true" ]] || return 0

    draw_box "DEBUG CONTAINERS — INTERNAL USE ONLY" \
        "You are about to install using private debug container" \
        "images from GHCR. These images are intended for internal" \
        "development and testing only. They are NOT suitable for" \
        "production use and are NOT publicly available." \
        "" \
        "Debug profile: ${OPT_DEBUG_PROFILE}" \
        "" \
        "Ensure you have a valid GitHub PAT with package:read" \
        "access to the llm-api-proxy organisation."

    if [[ "$OPT_NON_INTERACTIVE" == "true" ]]; then
        return 0
    fi

    if ! ask_yesno "Debug Containers" "Continue with debug containers?" "no"; then
        die "Aborted."
    fi
}

# Update PROXY_DEBUG and PROXY_DEBUG_PROFILE in an existing .env file.
# Uses sed for in-place updates (intentionally different from deploy_upgrade_env()
# which only appends missing keys — we need to UPDATE and REMOVE too).
deploy_upgrade_debug_state() {
    local env_file="${INSTALL_DIR}/docker/.env"
    [[ -f "$env_file" ]] || return 0

    if grep -qE '^PROXY_DEBUG=' "$env_file"; then
        # Update existing key
        $SUDO sed -i "s|^PROXY_DEBUG=.*|PROXY_DEBUG=${OPT_DEBUG}|" "$env_file"
    else
        # Append new key (upgrading from production to debug for first time)
        echo "PROXY_DEBUG=${OPT_DEBUG}" | $SUDO tee -a "$env_file" > /dev/null
    fi

    if [[ "$OPT_DEBUG" == "true" ]]; then
        if grep -qE '^PROXY_DEBUG_PROFILE=' "$env_file"; then
            $SUDO sed -i "s|^PROXY_DEBUG_PROFILE=.*|PROXY_DEBUG_PROFILE=${OPT_DEBUG_PROFILE}|" "$env_file"
        else
            echo "PROXY_DEBUG_PROFILE=${OPT_DEBUG_PROFILE}" | $SUDO tee -a "$env_file" > /dev/null
        fi
    else
        # Clear profile when disabling debug (prevent stale state)
        if grep -qE '^PROXY_DEBUG_PROFILE=' "$env_file"; then
            $SUDO sed -i "s|^PROXY_DEBUG_PROFILE=.*|PROXY_DEBUG_PROFILE=|" "$env_file"
        else
            # Append empty profile key so future loads have a consistent key present
            echo "PROXY_DEBUG_PROFILE=" | $SUDO tee -a "$env_file" > /dev/null
        fi
    fi
}

# ── Deploy phase: compose command, stack start, Consul ACL ───────────────────

deploy_write_compose_command() {
    step "  Generating compose-command.sh..."
    local cmd_file="${INSTALL_DIR}/compose-command.sh"

    local -a overlays=("docker-compose.yml" "docker-compose.hardened.yml")
    [[ "$OPT_WAF" == "true" ]] && overlays+=("docker-compose.waf.yml")
    [[ "$OPT_TLS" == "true" ]] && overlays+=("docker-compose.tls.yml")
    [[ "$OPT_MONITORING" == "true" ]] && overlays+=("docker-compose.monitoring.yml")
    [[ "$OPT_BACKUP" == "true" ]] && overlays+=("docker-compose.backup.yml")
    if [[ "$IS_MACOS" == "true" ]] && [[ "$MACOS_HOST_NETWORKING" == "true" ]]; then
        # Host networking available — no bridge overlay needed.
        # mDNS disabled via PROXY_MDNS__ENABLED=false in .env
        :
    elif [[ "$IS_MACOS" == "true" ]] || [[ "$OPT_MDNS" != "true" ]]; then
        overlays+=("docker-compose.no-mdns.yml")
    fi
    # Debug overlay must be last — overrides hardened overlay settings
    [[ "$OPT_DEBUG" == "true" ]] && overlays+=("docker-compose.debug.yml")

    local tmpfile
    tmpfile=$(mktemp)
    {
        echo '#!/bin/bash'
        echo "# compose-command.sh — single source of truth for running the stack."
        echo "# Generated by install.sh v${INSTALLER_VERSION}"
        echo 'set -euo pipefail'
        echo "cd \"${INSTALL_DIR}/docker\""
        echo -n 'exec docker compose'
        for overlay in "${overlays[@]}"; do
            echo " \\"
            echo -n "  -f ${overlay}"
        done
        echo " \\"
        # shellcheck disable=SC1003  # Backslash is a line continuation in the generated script
        echo '  --env-file .env \'
        echo '  "$@"'
    } > "$tmpfile"

    $SUDO mv "$tmpfile" "$cmd_file"
    $SUDO chmod 0750 "$cmd_file"
    if [[ "$IS_MACOS" != "true" ]]; then
        $SUDO chown "root:${SERVICE_USER}" "$cmd_file" 2>/dev/null || true
    fi
    info "compose-command.sh generated with overlays: ${overlays[*]}"
}

deploy_backup_compose_files() {
    if [[ ! -d "${INSTALL_DIR}/docker" ]]; then
        return 0
    fi
    local backup_dir
    backup_dir="${INSTALL_DIR}/compose-backup-$(date +%Y%m%d-%H%M%S)"
    $SUDO mkdir -p "$backup_dir"
    $SUDO cp "${INSTALL_DIR}"/docker/docker-compose*.yml "$backup_dir/" 2>/dev/null || true
    $SUDO cp "${INSTALL_DIR}/compose-command.sh" "$backup_dir/" 2>/dev/null || true
    info "Compose files backed up to ${backup_dir}"
}

deploy_pull_images() {
    step "  Pulling Docker images..."
    $SUDO "${INSTALL_DIR}/compose-command.sh" pull >> "$LOG_FILE" 2>&1 || {
        if [[ "$OPT_DEBUG" == "true" ]]; then
            local version_tag="${OPT_VERSION:-edge}-debug"
            local images="ghcr.io/llm-api-proxy/server-debug:${version_tag}"
            [[ "$OPT_BACKUP" == "true" ]] && images+=", ghcr.io/llm-api-proxy/backup-debug:${version_tag}"
            draw_box "FAILED: Pull debug Docker images" \
                "" \
                "Error pulling one or more private debug images:" \
                "  ${images}" \
                "" \
                "This usually means:" \
                "  • Your GitHub PAT lacks package:read access" \
                "  • The version tag '${version_tag}' doesn't exist" \
                "  • GHCR is temporarily unavailable" \
                "" \
                "Try:" \
                "  1. Verify your token: export CR_PAT=ghp_xxx" \
                "  2. Check available tags at: ghcr.io/llm-api-proxy/server-debug" \
                "  3. Re-run with: install.sh install --debug --github-token=ghp_xxx" \
                "" \
                "Full log: ${LOG_FILE}"
        else
            draw_box "FAILED: Pull Docker images" \
                "" \
                "Error pulling one or more images." \
                "" \
                "This usually means:" \
                "  • The version tag doesn't exist" \
                "  • GHCR is temporarily unavailable" \
                "  • Network/proxy is blocking the request" \
                "" \
                "Try:" \
                "  1. Check: ghcr.io/llm-api-proxy/server" \
                "  2. Run: docker pull <image> manually" \
                "  3. Re-run install.sh to retry" \
                "" \
                "Full log: ${LOG_FILE}"
        fi
        exit 1
    }
    info "Docker images pulled"
}

deploy_start_stack() {
    step "  Starting services..."
    # docker-compose.backup.yml declares proxy_ca_data as external:true.
    # Docker Compose validates all declared volumes before starting any
    # containers. Create the volume idempotently so compose up never fails
    # with "external volume not found" on the first install or after a purge.
    $SUDO docker volume create proxy_ca_data >> "$LOG_FILE" 2>&1 || true
    info "proxy_ca_data volume ready"

    # Start only the infrastructure services first. consul-init requires a
    # Consul ACL token which doesn't exist until deploy_consul_acl_bootstrap()
    # runs. Starting the full stack here would cause consul-init to exit 1
    # (no token) and abort compose up. The full stack is brought up after
    # ACL bootstrap in deploy_start_remaining_services().
    local -a bootstrap_services=("timescaledb" "consul")
    [[ "$OPT_MONITORING" == "true" ]] && bootstrap_services+=("prometheus" "grafana")
    $SUDO "${INSTALL_DIR}/compose-command.sh" up -d "${bootstrap_services[@]}" >> "$LOG_FILE" 2>&1

    local timeout=120
    local start_time
    start_time=$(date +%s)

    for svc in "${bootstrap_services[@]}"; do
        local status="starting"
        while [[ "$status" != "healthy" ]]; do
            status=$($SUDO docker inspect --format='{{.State.Health.Status}}' \
                "$($SUDO "${INSTALL_DIR}/compose-command.sh" ps -q "$svc" 2>/dev/null || true)" \
                2>/dev/null || echo "starting")

            local elapsed=$(( $(date +%s) - start_time ))
            if [[ $elapsed -ge $timeout ]]; then
                draw_box "FAILED: Health check timeout" \
                    "" \
                    "Service '${svc}' did not become healthy in ${timeout}s." \
                    "" \
                    "Check logs:" \
                    "  ${INSTALL_DIR}/compose-command.sh logs ${svc}" \
                    "" \
                    "Full log: ${LOG_FILE}"
                exit 1
            fi
            sleep 2
        done
        info "${svc} healthy"
    done
    info "Infrastructure services running"
}

deploy_start_remaining_services() {
    step "  Starting remaining services..."
    # Bring up the full stack now that Consul ACL tokens are in .env.
    # consul-init will succeed this time because CONSUL_HTTP_TOKEN is set.
    $SUDO "${INSTALL_DIR}/compose-command.sh" up -d >> "$LOG_FILE" 2>&1
    info "All services running"
}

deploy_consul_acl_bootstrap() {
    step "  Bootstrapping Consul ACLs..."

    local env_file="${INSTALL_DIR}/docker/.env"
    if grep -q "^CONSUL_HTTP_TOKEN=" "$env_file" 2>/dev/null && \
       grep -q "^BACKUP_CONSUL_HTTP_TOKEN=" "$env_file" 2>/dev/null && \
       grep -q "^PROXY_BACKUP_CONSUL_TOKEN=" "$env_file" 2>/dev/null; then
        info "Consul ACLs already bootstrapped — skipping"
        return 0
    fi

    local bootstrap_token=""
    local token_file="${METADATA_DIR}/consul-bootstrap-token"
    local attempts=0
    local max_attempts=3
    local delay=5

    if [[ -f "$token_file" ]]; then
        local candidate_token
        candidate_token=$($SUDO cat "$token_file")
        local consul_container_id
        consul_container_id=$($SUDO "${INSTALL_DIR}/compose-command.sh" ps -q consul 2>/dev/null || true)
        # Verify the saved token is still valid (consul volume may have been reset)
        if $SUDO docker exec \
            -e "CONSUL_HTTP_TOKEN=${candidate_token}" \
            -e "CONSUL_HTTP_ADDR=http://[::1]:8500" \
            "$consul_container_id" \
            consul acl token read -self -format=json > /dev/null 2>&1; then
            bootstrap_token="$candidate_token"
            info "Using existing bootstrap token from ${token_file}"
        else
            log "Saved bootstrap token is no longer valid (consul volume may have been reset) — bootstrapping fresh"
            $SUDO rm -f "$token_file"
        fi
    fi
    if [[ -z "$bootstrap_token" ]]; then
        local bootstrap_error=""
        while [[ $attempts -lt $max_attempts ]]; do
            local result
            if result=$($SUDO docker exec \
                -e "CONSUL_HTTP_ADDR=http://[::1]:8500" \
                "$($SUDO "${INSTALL_DIR}/compose-command.sh" ps -q consul 2>/dev/null || true)" \
                consul acl bootstrap -format=json 2>&1); then
                bootstrap_token=$(echo "$result" | jq -r '.SecretID' 2>/dev/null || true)
                break
            else
                bootstrap_error="$result"
            fi
            attempts=$((attempts + 1))
            if [[ $attempts -lt $max_attempts ]]; then
                log "ACL bootstrap attempt ${attempts} failed, retrying in ${delay}s..."
                sleep "$delay"
                delay=$((delay * 2))
            fi
        done

        if [[ -z "$bootstrap_token" ]]; then
            # Detect "already bootstrapped" — occurs when reinstalling without --purge
            # and the consul volume still has ACL state from a prior install
            if echo "$bootstrap_error" | grep -qiE "no longer allowed|bootstrap.*done|ACL bootstrap already"; then
                draw_box "FAILED: Consul ACLs already bootstrapped" \
                    "" \
                    "Consul ACLs were bootstrapped in a previous install but the" \
                    "bootstrap token file is missing from ${METADATA_DIR}." \
                    "" \
                    "Recovery options:" \
                    "  1. Re-run with --purge to reset all state (DATA LOSS)" \
                    "  2. Manually recover the bootstrap token:" \
                    "       docker exec -it <consul-container> consul acl token list" \
                    "     Then save it to: ${token_file}" \
                    "" \
                    "Full log: ${LOG_FILE}"
            else
                draw_box "FAILED: Consul ACL bootstrap" \
                    "" \
                    "Could not bootstrap Consul ACLs after ${max_attempts} attempts." \
                    "" \
                    "Last error: ${bootstrap_error}" \
                    "" \
                    "Manual bootstrap:" \
                    "  docker exec -it <consul-container> consul acl bootstrap" \
                    "" \
                    "Full log: ${LOG_FILE}"
            fi
            exit 1
        fi

        echo "$bootstrap_token" | $SUDO tee "$token_file" > /dev/null
        $SUDO chmod 0600 "$token_file"
        $SUDO chown root:root "$token_file" 2>/dev/null || true
        info "Bootstrap token stored at ${token_file} (root-only)"
    fi

    local consul_container
    consul_container=$($SUDO "${INSTALL_DIR}/compose-command.sh" ps -q consul 2>/dev/null || true)

    # consul-init-rw policy
    $SUDO docker exec -e "CONSUL_HTTP_TOKEN=${bootstrap_token}" -e "CONSUL_HTTP_ADDR=http://[::1]:8500" "$consul_container" \
        consul acl policy create -name consul-init-rw \
        -rules='key_prefix "traefik/" { policy = "write" }' 2>/dev/null || true
    local consul_init_token
    consul_init_token=$($SUDO docker exec -e "CONSUL_HTTP_TOKEN=${bootstrap_token}" -e "CONSUL_HTTP_ADDR=http://[::1]:8500" "$consul_container" \
        consul acl token create -policy-name consul-init-rw \
        -description "consul-init KV writer" -format=json 2>/dev/null | jq -r '.SecretID // empty' 2>/dev/null || true)
    if [[ -z "$consul_init_token" ]]; then
        warn "Failed to create consul-init token — ACL bootstrap token may be invalid"
        exit 1
    fi

    # backup-agent-write policy
    $SUDO docker exec -e "CONSUL_HTTP_TOKEN=${bootstrap_token}" -e "CONSUL_HTTP_ADDR=http://[::1]:8500" "$consul_container" \
        consul acl policy create -name backup-agent-write \
        -rules='key_prefix "proxy/backup/" { policy = "write" }' 2>/dev/null || true
    local backup_token
    backup_token=$($SUDO docker exec -e "CONSUL_HTTP_TOKEN=${bootstrap_token}" -e "CONSUL_HTTP_ADDR=http://[::1]:8500" "$consul_container" \
        consul acl token create -policy-name backup-agent-write \
        -description "Backup agent KV writer" -format=json 2>/dev/null | jq -r '.SecretID // empty' 2>/dev/null || true)
    if [[ -z "$backup_token" ]]; then
        warn "Failed to create backup consul token — ACL bootstrap token may be invalid"
        exit 1
    fi

    # proxy-server-backup-rw policy
    $SUDO docker exec -e "CONSUL_HTTP_TOKEN=${bootstrap_token}" -e "CONSUL_HTTP_ADDR=http://[::1]:8500" "$consul_container" \
        consul acl policy create -name proxy-server-backup-rw \
        -rules='key_prefix "proxy/backup/" { policy = "write" }' 2>/dev/null || true
    local proxy_backup_token
    proxy_backup_token=$($SUDO docker exec -e "CONSUL_HTTP_TOKEN=${bootstrap_token}" -e "CONSUL_HTTP_ADDR=http://[::1]:8500" "$consul_container" \
        consul acl token create -policy-name proxy-server-backup-rw \
        -description "Proxy server backup KV" -format=json 2>/dev/null | jq -r '.SecretID // empty' 2>/dev/null || true)
    if [[ -z "$proxy_backup_token" ]]; then
        warn "Failed to create proxy backup consul token — ACL bootstrap token may be invalid"
        exit 1
    fi

    local tmpenv
    tmpenv=$(mktemp); CLEANUP_FILES+=("$tmpenv")
    $SUDO cat "$env_file" > "$tmpenv"
    cat >> "$tmpenv" <<ACLEOF

# ── Consul ACL (provisioned by installer) ────────────────────
CONSUL_HTTP_TOKEN=${consul_init_token}
BACKUP_CONSUL_HTTP_TOKEN=${backup_token}
PROXY_BACKUP_CONSUL_TOKEN=${proxy_backup_token}
ACLEOF
    $SUDO chmod 0640 "$tmpenv"
    if [[ "$IS_MACOS" != "true" ]]; then
        $SUDO chown "root:${SERVICE_USER}" "$tmpenv" 2>/dev/null || true
    fi
    $SUDO mv "$tmpenv" "$env_file"

    log "Consul tokens: init=$(mask_secret "$consul_init_token") backup=$(mask_secret "$backup_token")"

    $SUDO "${INSTALL_DIR}/compose-command.sh" run --rm consul-init >> "$LOG_FILE" 2>&1 || true

    $SUDO "${INSTALL_DIR}/compose-command.sh" restart proxy >> "$LOG_FILE" 2>&1
    if [[ "$OPT_BACKUP" == "true" ]]; then
        $SUDO "${INSTALL_DIR}/compose-command.sh" restart backup >> "$LOG_FILE" 2>&1 || true
    fi

    info "Consul ACLs bootstrapped with scoped tokens"
}

# ── Deploy: system service ───────────────────────────────────────────────────

deploy_install_service() {
    step "  Installing system service..."

    if [[ "$IS_MACOS" == "true" ]]; then
        local plist_dir="${HOME}/Library/LaunchAgents"
        mkdir -p "$plist_dir"
        local plist_file="${plist_dir}/com.llm-api-proxy.plist"
        cat > "$plist_file" <<PLISTEOF
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
    <key>Label</key>
    <string>com.llm-api-proxy</string>
    <key>ProgramArguments</key>
    <array>
        <string>${INSTALL_DIR}/compose-command.sh</string>
        <string>up</string>
        <string>-d</string>
    </array>
    <key>RunAtLoad</key>
    <true/>
    <key>KeepAlive</key>
    <false/>
    <key>WorkingDirectory</key>
    <string>${INSTALL_DIR}/docker</string>
</dict>
</plist>
PLISTEOF
        launchctl load "$plist_file" 2>/dev/null || true
        info "launchd service installed"
        return 0
    fi

    local unit_file="/etc/systemd/system/llm-api-proxy.service"
    $SUDO tee "$unit_file" > /dev/null <<UNITEOF
[Unit]
Description=LLM API Proxy
Documentation=https://llm-api-proxy.com/docs
After=docker.service
Requires=docker.service

[Service]
Type=oneshot
RemainAfterExit=yes
User=${SERVICE_USER}
Group=${SERVICE_USER}
WorkingDirectory=${INSTALL_DIR}/docker
ExecStart=${INSTALL_DIR}/compose-command.sh up -d
ExecStop=${INSTALL_DIR}/compose-command.sh down
ExecReload=${INSTALL_DIR}/compose-command.sh up -d
TimeoutStartSec=120
TimeoutStopSec=60

[Install]
WantedBy=multi-user.target
UNITEOF

    $SUDO systemctl daemon-reload
    $SUDO systemctl enable llm-api-proxy >> "$LOG_FILE" 2>&1
    info "systemd service installed and enabled"
}

# ── Deploy: install metadata ─────────────────────────────────────────────────

deploy_write_metadata() {
    step "  Writing install metadata..."
    local meta_file="${METADATA_DIR}/install.json"

    local features="["
    [[ "$OPT_WAF" == "true" ]] && features+='"waf",'
    [[ "$OPT_TLS" == "true" ]] && features+='"tls",'
    [[ "$OPT_BACKUP" == "true" ]] && features+='"backup",'
    [[ "$OPT_MONITORING" == "true" ]] && features+='"monitoring",'
    [[ "$OPT_MDNS" == "true" ]] && features+='"mdns",'
    features="${features%,}]"

    $SUDO tee "$meta_file" > /dev/null <<METAEOF
{
  "install_dir": "${INSTALL_DIR}",
  "installed_at": "$(date -u +%Y-%m-%dT%H:%M:%SZ)",
  "installed_by": "install.sh ${INSTALLER_VERSION}",
  "version": "${OPT_VERSION}",
  "os": "${OS_ID}-${OS_VERSION}",
  "arch": "${ARCH}",
  "features": ${features},
  "tos_accepted_at": "${TOS_ACCEPTED_AT:-}",
  "tos_sha256": "${TOS_SHA256:-}",
  "tos_accepted_by": "$(whoami)"
}
METAEOF

    $SUDO chmod 0644 "$meta_file"
    echo "${OPT_VERSION}" | $SUDO tee "${INSTALL_DIR}/.version" > /dev/null
    info "Metadata written to ${meta_file}"
}

# ── Deploy: open browser ─────────────────────────────────────────────────────

deploy_open_browser() {
    if [[ "$OPT_NON_INTERACTIVE" == "true" ]]; then
        return 0
    fi

    local url
    if [[ "$OPT_TLS" == "true" ]]; then
        url="https://${OPT_DOMAIN}"
    else
        local ip
        ip=$(ip -6 addr show scope global 2>/dev/null | awk '/inet6 /{split($2,a,"/"); print a[1]; exit}' || true)
        [[ -z "$ip" ]] && ip=$(hostname -I 2>/dev/null | awk '{print $1}' || echo "localhost")
        url="http://${ip}"
    fi

    if [[ "$IS_MACOS" == "true" ]]; then
        open "$url" 2>/dev/null || true
    elif [[ -n "${DISPLAY:-}" ]] || [[ -n "${WAYLAND_DISPLAY:-}" ]]; then
        if command -v xdg-open &>/dev/null; then
            xdg-open "$url" 2>/dev/null || true
        fi
    fi
}

# ── Deploy: post-install summary ─────────────────────────────────────────────

deploy_post_install_summary() {
    local url service_cmd log_cmd
    if [[ "$OPT_TLS" == "true" ]]; then
        url="https://${OPT_DOMAIN}"
    else
        local ip
        ip=$(ip -6 addr show scope global 2>/dev/null | awk '/inet6 /{split($2,a,"/"); print a[1]; exit}' || true)
        [[ -z "$ip" ]] && ip=$(hostname -I 2>/dev/null | awk '{print $1}' || echo "localhost")
        url="http://${ip}"
    fi

    if [[ "$IS_MACOS" == "true" ]]; then
        service_cmd="launchctl list | grep llm-api-proxy"
        log_cmd="${INSTALL_DIR}/compose-command.sh logs -f"
    else
        service_cmd="systemctl status llm-api-proxy"
        log_cmd="${INSTALL_DIR}/compose-command.sh logs -f"
    fi

    draw_box "Installation complete!" \
        "" \
        "Dashboard:  ${url}" \
        "Status:     ${service_cmd}" \
        "Logs:       ${log_cmd}" \
        "Config:     ${INSTALL_DIR}/docker/.env" \
        "" \
        "Complete the setup wizard in your browser" \
        "to create your first admin account." \
        "" \
        "Useful commands:" \
        "  Restart: systemctl restart llm-api-proxy" \
        "  Stop:    systemctl stop llm-api-proxy" \
        "  Upgrade: re-run install.sh" \
        "" \
        "Docs: https://llm-api-proxy.com/docs"
}

# ── Deploy: orchestrator ─────────────────────────────────────────────────────

run_deploy() {
    step "[5/5] Deploying..."

    if [[ "$COMMAND" == "upgrade" ]]; then
        deploy_backup_compose_files
    fi

    deploy_create_dirs
    deploy_extract_files

    if [[ "$COMMAND" == "upgrade" ]]; then
        deploy_upgrade_env
    else
        deploy_write_env
    fi

    deploy_write_compose_command
    ghcr_login
    deploy_pull_images
    deploy_start_stack
    deploy_consul_acl_bootstrap
    deploy_start_remaining_services
    configure_nftables_docker_forward
    deploy_install_service
    deploy_write_metadata
    deploy_post_install_summary
    deploy_open_browser
}

# ── Uninstall ────────────────────────────────────────────────────────────────

run_uninstall() {
    step "Uninstalling LLM API Proxy..."

    local meta_file="${METADATA_DIR:-/etc/llm-api-proxy}/install.json"
    if [[ -f "$meta_file" ]]; then
        INSTALL_DIR=$(jq -r '.install_dir' "$meta_file" 2>/dev/null || echo "$INSTALL_DIR")
    fi

    if [[ ! -d "$INSTALL_DIR" ]]; then
        die "No installation found at ${INSTALL_DIR}"
    fi

    if [[ -x "${INSTALL_DIR}/compose-command.sh" ]]; then
        $SUDO "${INSTALL_DIR}/compose-command.sh" down >> "$LOG_FILE" 2>&1 || true
        info "Stack stopped"
    fi

    if [[ "$IS_MACOS" == "true" ]]; then
        local plist="${HOME}/Library/LaunchAgents/com.llm-api-proxy.plist"
        launchctl unload "$plist" 2>/dev/null || true
        rm -f "$plist"
    else
        $SUDO systemctl stop llm-api-proxy 2>/dev/null || true
        $SUDO systemctl disable llm-api-proxy 2>/dev/null || true
        $SUDO rm -f /etc/systemd/system/llm-api-proxy.service
        $SUDO systemctl daemon-reload 2>/dev/null || true
    fi
    info "System service removed"

    $SUDO rm -rf "$INSTALL_DIR"
    info "Install directory removed: ${INSTALL_DIR}"

    if [[ "$IS_MACOS" != "true" ]] && id "$SERVICE_USER" &>/dev/null; then
        $SUDO userdel "$SERVICE_USER" 2>/dev/null || true
        info "System user '${SERVICE_USER}' removed"
    fi

    $SUDO rm -rf "$METADATA_DIR"
    info "Metadata removed"

    if [[ "$OPT_PURGE" == "true" ]]; then
        echo ""
        warn "WARNING: --purge will delete ALL data including the database!"
        if [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
            local confirm
            read -r -p "  Type YES to confirm volume deletion: " confirm
            if [[ "$confirm" != "YES" ]]; then
                info "Volume purge cancelled"
                return 0
            fi
        fi

        local -a volumes=("docker_timescaledb_data" "docker_consul_data")
        $SUDO docker volume rm "${volumes[@]}" 2>/dev/null || true
        $SUDO docker volume rm "docker_acme_data" "docker_proxy_ca_data" 2>/dev/null || true
        $SUDO docker volume rm "docker_prometheus_data" "docker_grafana_data" 2>/dev/null || true
        info "Docker volumes purged"
    fi

    info "Uninstall complete"
}

# ── Source-only mode for testing ──────────────────────────────────────────────
# When sourced by BATS with --source-only, all functions above are now defined.
# Return here to skip the main execution block below.
# shellcheck disable=SC2317  # Intentional: `return` succeeds when sourced; `exit` is the fallback for `bash file.sh --source-only`
if [[ "${1:-}" == "--source-only" ]]; then
    return 0 2>/dev/null || exit 0
fi

# ── Main entry point ─────────────────────────────────────────────────────────

main() {
    log_init "$@"
    parse_args "$@"
    apply_env_defaults

    # Auto-detect pipe execution: if stdin is not a tty, force non-interactive
    # mode. Interactive prompts (dialog, read) cannot work when piped.
    if [[ ! -t 0 ]] && [[ "$OPT_NON_INTERACTIVE" != "true" ]]; then
        OPT_NON_INTERACTIVE="true"
        OPT_ACCEPT_TOS="true"
        log "Auto-detected pipe execution (stdin is not a tty) — forcing non-interactive mode"
    fi

    resolve_github_token
    if [[ -n "${GITHUB_TOKEN_RESOLVED:-}" ]]; then
        detect_github_user
    fi
    detect_dialog
    detect_os
    load_debug_state_from_env
    warn_debug_mode
    detect_arch

    case "${COMMAND:-}" in
        uninstall)
            run_uninstall
            exit 0
            ;;
    esac

    INSTALL_PHASE="preflight"
    run_preflight

    INSTALL_PHASE="legal"
    run_tos

    INSTALL_PHASE="prepare"
    run_prepare

    INSTALL_PHASE="configure"
    run_configure

    INSTALL_PHASE="deploy"
    run_deploy

    INSTALL_PHASE=""
    info "Installation complete!"
}

